INSERT INTO public.ethics_codes (code, title, full_text, source, article_number, tier, tier_rationale, parent_code_id, domain, locale, version, is_active, effective_from, is_citable)
VALUES
  ('JEC-P', '언론윤리헌장 서문', '언론은 시민을 위해 존재하며, 시민의 신뢰는 언론의 가장 소중한 자산이다. 시민의 알권리를 충족하고 민주주의 가치를 실현하기 위해 자유롭고 책임 있는 언론이 필요하다. 언론은 인권을 옹호하며, 정의롭고 평화로운 공동체를 추구한다. 이를 위해 정확하고 공정한 보도를 통해 시민의 올바른 판단과 의사소통을 도우며, 다양한 가치와 의견을 균형 있게 대변함으로써 사회 통합을 위해 노력한다. 아울러 권력을 감시하고 비판해 사회 정의를 실현하고 민주주의를 발전시키는 데 기여한다. 날로 다원화하는 언론 환경에서 저널리즘의 원칙과 책무에 충실한 윤리적 언론은 시대의 요청이다. 이에 우리는 매체와 분야, 형태에 관계없이 보도와 논평에 종사하는 모든 언론인이 실천해야 할 핵심 원칙을 담아 언론윤리헌장을 선언한다.', '언론윤리헌장', '서문', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('JEC-1', '진실을 추구한다', '윤리적 언론은 진실을 보도한다. 진실 추구는 언론의 존재 이유다. 사실을 부정하고 믿고 싶은 바를 진실로 받아들이는 시대에 진실 추구의 중요성은 그 어느 때보다 크다. 윤리적 언론은 정확한 사실을 종합적이고 포괄적인 맥락으로 전달한다. 정확성은 신속성에 우선한다. 모든 정보를 성실하게 검증하고 명확한 근거를 바탕으로 보도한다. 취재원 발언을 정확히 인용하며 발언 취지가 왜곡되지 않도록 한다. 진실을 밝히기 위해 용기 있고 성실한 태도를 견지한다. 사실과 의견을 분리하고, 의도와 기술방식이 진실을 가리지 않도록 양심에 따라 보도한다.', '언론윤리헌장', '제1조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-2', '투명하게 보도하고 책임 있게 설명한다', '윤리적 언론은 정보원과 취재 과정 등을 가능한 한 투명하게 알리고, 문제 제기에 책임 있게 설명한다. 윤리적 언론은 독자와 시청자가 정보에 대해 스스로 판단할 수 있도록, 취재원 보호 등 필요한 경우를 제외하고는 정보의 출처를 명확히 밝힌다. 보도에 대한 의문과 비판에 열린 자세로 소통하며, 잘못이 있다면 신속하고 분명하게 바로잡는다. 보도에 영향을 미친 외부 지원과 후원 및 이해상충 소지 등에 대해서도 정직하게 밝힌다. 투명성과 설명책임은 언론인 개인뿐 아니라 언론사 조직의 공동책임이다.', '언론윤리헌장', '제2조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-3', '인권을 존중하고 피해를 최소화한다', '윤리적 언론은 취재 대상을 존중한다. 공공의 이익을 위해 보도할 가치가 있는 정보를 취재하고 전달할 경우에도 개인의 인권과 존엄성을 침해하지 않도록 한다. 특히 미숙하고 동의 능력이 없는 취재원, 사건 피해자 등을 취재할 때는 절차적 정당성과 가장 높은 수준의 인권 감수성을 가지고 주의를 기울인다. 합법적으로 획득한 정보라도 이를 보도할 때는 윤리적 정당성을 갖춰야 한다. 공인이 아닌 일반 시민에 대해 보도할 때는 인격권 보호에 더욱 주의한다. 피의자가 공정한 재판을 받을 권리와 공중의 알권리 사이의 균형을 추구한다.', '언론윤리헌장', '제3조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-4', '공정하게 보도한다', '윤리적 언론은 특정 집단, 세력, 견해에 치우치지 않고 공평무사한 자세로 보도한다. 사회적으로 중요한 사안이나 갈등적 사안을 다룰 때는 다양한 입장을 두루 담아 전체를 아우르는 균형 잡힌 시각과 관점을 보여준다. 윤리적 언론은 시시비비를 가리는 언론 본연의 역할에 충실하면서도 사회 내에 존재하는 다양한 의견의 경중을 고려해 보도 내용의 양적·질적 균형을 맞춘다. 특정한 가치와 정파적 이익에 부합하는 사실과 견해만을 선택하거나 과장하지 않는다. 기사로 인해 불이익을 볼 수 있는 개인이나 집단에는 자신을 방어하고 반론할 권리를 보장한다.', '언론윤리헌장', '제4조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-5', '독립적으로 보도한다', '윤리적 언론은 모든 권력으로부터 독립해 오로지 시민과 공익의 관점에서 자율적이고 전문적으로 판단한다. 언론사 안팎의 부당한 간섭과 압력을 거부하고 언론의 자유와 보도의 자율성을 지킨다. 독립적인 보도를 보장하기 위해 편집과 경영의 분리 원칙을 준수한다. 이를 바탕으로 모든 형태의 권력을 감시한다. 독자와 시청자의 의견과 비판을 겸허하게 경청하고 보도에 반영하되, 건전한 비판 보도를 막으려는 의도적이고 집단적인 공격에 위축되지 않는다. 상업적 이해가 보도에 영향을 미치지 않도록 한다.', '언론윤리헌장', '제5조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-6', '갈등을 풀고 신뢰를 북돋우는 토론장을 제공한다', '윤리적 언론은 다양한 사회집단과 세력이 자신들의 의사를 표현하고 소통함으로써 합의를 모색하는 공론의 장을 제공한다. 다양한 사람의 참여를 보장하고, 이들의 의견이 공정하게 전달되고 교류되도록 한다. 대립하는 관점과 주장이 표출되고 조정될 수 있는 토론장을 제공함으로써 사회가 갈등과 이질성을 조화롭게 극복할 수 있도록 돕는다. 윤리적 언론은 사회적 신뢰를 창출하고, 공동체가 믿음에 기초해 운영되도록 제 역할을 다한다. 진영논리에 빠져 특정 세력을 편들거나 반대 세력을 과도하게 공격하지 않으며, 차이와 불화를 침소봉대해 갈등을 극대화하는 보도 태도를 지양한다. 역사적 사실을 부정하는 시도에 대해서는 그 배경과 맥락을 파악해 비판적으로 전달한다.', '언론윤리헌장', '제6조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-7', '다양성을 존중하고 차별에 반대한다', '윤리적 언론은 모든 사람이 존중받는 세상을 위해 차별과 편견을 줄이려 노력한다. 언론은 다양한 사회적 가치와 문화적 차이를 인정하고 이를 존중한다. 언론은 성별, 장애, 종교, 나이, 출신 지역, 인종, 성적 지향 등을 이유로 누구도 부당하게 차별받지 않도록 감시한다. 편견과 차별이 발생하는 구조를 발굴·보도해 사회적 의제로 확산시킨다. 고정관념과 편견을 부추기는 표현, 특정 계층·지역을 비하하는 표현, 성차별 표현, 사람을 성적으로 대상화하는 표현을 삼간다.', '언론윤리헌장', '제7조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-8', '품위 있게 행동하며 이해상충을 경계한다', '윤리적 언론은 높은 도덕성을 유지하고 언론의 힘을 사적으로 남용하지 않으며 이해상충을 경계하고 예방한다. 언론인과 언론사의 도덕적이고 품위 있는 행동은 권력과 사회를 감시하고 비판하는 언론 활동에 정당성을 부여한다. 윤리적 언론은 취재보도 과정에서 정당한 방법을 사용하고, 취재원에게 예의를 갖춘다. 또 올바르고 품격 있는 언어를 쓰도록 노력한다. 취재원과는 공과 사를 분명히 구분하고, 적절한 긴장 관계를 유지한다. 취재 과정에서 알게 된 정보를 이용해 금전적 또는 사적 이익을 추구하지 않는다. 취재원으로부터 정당한 이유가 없는 혜택과 편의를 제공받지 않으며 부당한 청탁이나 압력을 행사하지 않는다.', '언론윤리헌장', '제8조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JEC-9', '디지털 기술로 저널리즘의 가능성을 확장한다', '윤리적 언론은 디지털 기술이 언론 활동에 미치는 변화를 적극 수용하고, 뉴스의 생산·유통·소비의 전 과정에서 기술이 독자와 시민에게 유익하게 활용되도록 노력한다. 참여와 공유를 통해 시민과의 소통을 확대하고 상호 협력해 뉴스를 생산하고 내용을 발전시킨다. 인터넷과 소셜미디어 등을 통한 취재는 익명성을 악용한 허위정보와 여론 조작 위험 등을 감안해 더욱 신중하게 사실을 검증한다. 다른 언론사 기사를 복제하거나 표절하지 않으며, 독자적으로 취재하고 작성해 보도한다. 독자의 주목을 끌기 위해 선정적이거나 오도하는 제목을 쓰지 않으며 기사를 수정했을 경우 수정의 내용과 이유를 독자가 알 수 있게 표시한다. 온라인 콘텐츠를 사용할 때는 작성자의 동의를 구하고 저작권을 보호한다.', '언론윤리헌장', '제9조', 1, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-P', '기자윤리강령 서문', '기자는 국민의 알 권리를 충족시키고, 진실을 알릴 의무를 가진 언론의 최일선 핵심존재로서 공정보도를 실천할 사명을 띠고 있으며, 이를 위해 국민으로부터 언론이 위임받은 편집편성권을 공유할 권리를 갖는다. 기자는 자유로운 언론활동을 통해 나라의 민주화에 기여하고 국가발전을 위해 국민들을 올바르게 계도할 책임과 함께, 평화통일·민족화합·민족의 동질성 회복에 기여해야 할 시대적 소명을 안고 있다. 이와같이 막중한 책임과 사명을 갖고 있는 기자에게는 다른 어떤 직종의 종사자들보다도 투철한 직업윤리가 요구된다. 이에 한국기자협회는 회원들이 지켜야 할 행동기준으로서 윤리강령과 그 실천요강을 제정하여 이의 준수와 실천을 선언한다.', '기자윤리강령', '서문', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('JCE-1', '언론자유 수호', '우리는 권력과 금력 등 언론의 자유를 위협하는 내외부의 개인 또는 집단의 어떤 부당한 간섭이나 압력도 단호히 배격한다.', '기자윤리강령', '제1조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-2', '공정보도', '우리는 뉴스를 보도함에 있어서 진실을 존중하여 정확한 정보만을 취사선택하며, 엄정한 객관성을 유지한다.', '기자윤리강령', '제2조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-3', '품위유지', '우리는 취재 보도의 과정에서 기자의 신분을 이용해 부당이득을 취하지 않으며, 취재원으로부터 제공되는 사적인 특혜나 편의를 거절한다.', '기자윤리강령', '제3조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-4', '정당한 정보수집', '우리는 취재과정에서 항상 정당한 방법으로 정보를 취득하며, 기록과 자료를 조작하지 않는다.', '기자윤리강령', '제4조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-5', '올바른 정보사용', '우리는 취재활동 중에 취득한 정보를 보도의 목적에만 사용한다.', '기자윤리강령', '제5조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-6', '사생활 보호', '우리는 개인의 명예를 해치는 사실무근한 정보를 보도하지 않으며, 보도대상의 사생활을 보호한다.', '기자윤리강령', '제6조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-7', '취재원 보호', '우리는 어떠한 경우에도 취재원을 보호한다.', '기자윤리강령', '제7조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-8', '오보의 정정', '우리는 잘못된 보도에 대해서는 솔직하게 시인하고, 신속하게 바로 잡는다.', '기자윤리강령', '제8조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-9', '갈등·차별 조장 금지', '우리는 취재와 과정및 보도의 내용에서 지역·계층·종교·상집단간의 갈등을 유발하거나, 차별을 조장하지 않는다.', '기자윤리강령', '제9조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCE-10', '광고·판매활동의 제한', '우리는 소속회사의 판매 및 광고문제와 관련, 기자로서의 품위를 손상하는 일체의 행동을 하지 않는다.', '기자윤리강령', '제10조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-P', '기자윤리실천요강 서문', '본 실천요강은 윤리강령을 실천하기 위한 구체적인 행동지침을 규정하며, 강령 및 본 실천요강의 규정을 회원들이 철저하게 준수하도록 하기 위한 실천기구로 협회내에 韓國記者協會 倫理委員會(記協 倫理委)를 별도의 규정에 따라 구성 운영한다.', '기자윤리실천요강', '서문', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('JCP-1-1', '언론자유 침해에 대한 단호한 대처', '회원은 언론자유를 침해하는 내·외부의 어떤 간섭과 압력에도 굴하지 않으며, 언론자유를 위협하는 개인이나 집단에 대해서 단호히 대처한다.', '기자윤리실천요강', '1장 1항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-1-2', '보도자유분과위원회에 침해사례 고발', '회원은 언론자유를 침해하는 사태가 발생할 경우 협회 보도자유분과위원회에 침해사례를 즉각 고발하여 이를 시정토록 한다.', '기자윤리실천요강', '1장 2항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-1-3', '정보 접근권 및 비판·논평 권리 보장', '회원은 언론의 자유로운 정보 접근권과 비판 및 논평의 권리가 보장되도록 노력한다.', '기자윤리실천요강', '1장 3항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-1', '객관적 사실에 입각한 진실보도', '회원은 기자의 제 1사명이 공정보도임을 명심하고, 객관적 사실에 입각한 진실보도를 위해 최선을 다한다.', '기자윤리실천요강', '2장 1항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-2', '이해관계 사안에서 형평과 공정성 유지', '회원은 이해관계가 얽힌 사안의 취재 및 보도활동에 있어서 취재원에 대해 형평과 공정성을 유지해야 한다.', '기자윤리실천요강', '2장 2항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-3', '개인적 목적에 영합하는 취재보도 금지', '회원은 본인 또는 취재원의 개인적인 목적에 영합하는 취재 보도활동을 해서는 안된다.', '기자윤리실천요강', '2장 3항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-4', '확증 없는 추측보도 지양', '회원은 확증을 갖지 않는 내용에 대한 추측보도를 지양한다.', '기자윤리실천요강', '2장 4항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-5', '위계·강압적 정보 취득 금지', '회원은 정보를 취득함에 있어서 위계(僞計) 나 강압적인 방법을 쓰지 않는다.', '기자윤리실천요강', '2장 5항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-6', '기록·자료 임의 조작 금지', '회원은 기록과 자료를 사용함에 있어서 이를 임의로 조작하여 사용하지 않는다.', '기자윤리실천요강', '2장 6항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-7', '개인 명예 손상 주의', '회원은 고의든 고의가 아니든 간에 개인의 명예를 손상하지 않도록 주의를 다한다.', '기자윤리실천요강', '2장 7항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-8', '공익 우선이 아닌 한 사생활 보호', '회원은 공익이 우선하지 않는 한 모든 취재 보도 대상의 사생활이 침해되지 않도록 최선을 다한다.', '기자윤리실천요강', '2장 8항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-9', '비밀 취득 정보의 취재원 보호', '회원은 비밀리에 정보를 취득했을 경우, 취재원을 철처히 보호한다.', '기자윤리실천요강', '2장 9항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-10', '오보 시인 및 신속 정정보도', '회원은 오보가 발생했을 때는 잘못을 솔직하게 시인, 가능한 빨리 이를 정정보도한다.', '기자윤리실천요강', '2장 10항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-2-11', '갈등 유발·차별 조장 보도 지양', '회원은 지역·계층·종교·성·집단간의 문제를 다룸에 있어 상호간의 갈등을 유발하거나, 차별을 조장하지 않도록 보도에 신중을 기한다.', '기자윤리실천요강', '2장 11항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-3-1', '금품·특혜·향응 거부', '회원은 취재원으로부터 제공되는 일체의 금품, 특혜, 향응을 받아서는 안 되며, 무료여행, 접대골프도 이에 해당한다.', '기자윤리실천요강', '3장 1항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-3-2', '취재원 앞 저급한 언행 삼가기', '회원은 취재과정에서 취재원으로부터 비난받을 여지가 있는 저급한 언행을 삼간다.', '기자윤리실천요강', '3장 2항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-3-3', '기자단·기자실의 이익 목적 운영 방지', '회원은 출입처의 기자단 및 기자실이 취재활동의 편의 이외의 집단 또는 개인의 이익을 취할 목적으로 운영되지 않도록 한다.', '기자윤리실천요강', '3장 3항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-3-4', '보도편의만을 위한 엠바고·불합리한 담합 삼가기', '회원은 출입처 기자단의 단순한 보도편의만을 위한 [ 엠바고 ]와 불합리한 담합을 삼간다.', '기자윤리실천요강', '3장 4항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-3-5', '취득 정보의 사적 이익 사용 금지', '회원은 취재 보도과정에서 취득한 정보를 개인이나 특정 집단의 이익추구에 사용하지 않는다.', '기자윤리실천요강', '3장 5항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('JCP-3-6', '출판물 강매·광고 강요 및 취재보도 연계 금지', '회원은 소속회사의 출판물 강매 및 광고 강요행위를 하지 않으며, 이를 취재보도와 연계하지 않는다.', '기자윤리실천요강', '3장 6항', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-P', '신문윤리강령 서문', '우리 언론인은 자유롭고 책임 있는 언론을 실현해 주어진 사명을 다할 것을 다짐한다. 자유롭고 책임 있는 언론은 민주발전, 사회통합, 민족화합과 평화통일, 문화창달에 크게 기여한다고 믿는다. 우리는 이러한 신념에 따라 스스로 윤리규범을 준수하기 위해 1957년 4월 7일「신문윤리강령」을 처음 제정했다. 이제 그 숭고한 정신을 바탕으로 한국신문협회, 한국신문방송편집인협회, 한국기자협회는 언론 환경과 시대 변화에 맞춰 새로운 신문윤리강령을 다시 채택한다.', '신문윤리강령', '서문', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('PCE-1', '언론의 자유', '우리 언론인은 언론의 자유가 국민의 알 권리를 실현하기 위한 으뜸가는 가치임을 깊이 인식하고 대내외적인 모든 침해, 압력, 제한으로부터 이 자유를 지킬 것을 다짐한다.', '신문윤리강령', '제1조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-2', '언론의 책임', '우리 언론인은 언론이 사회의 공기로서 막중한 책임을 지고 있다고 믿는다. 이에 다양한 여론을 형성하고 국민의 기본권을 보호, 신장하기 위해 적극적으로 노력한다. 또한 공공복지 증진, 민족화합, 문화창달 등을 위해 전력을 다할 것을 다짐한다.', '신문윤리강령', '제2조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-3', '언론의 독립', '우리 언론인은 언론이 정치, 경제, 사회, 종교 등 외부 세력으로부터 독립된 자주성을 갖고 있음을 천명한다. 우리는 언론에 대한 일체의 간섭과 부당한 이용을 단호히 거부할 것을 다짐한다.', '신문윤리강령', '제3조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-4', '보도와 평론', '우리 언론인은 사실의 전모를 정확하고, 객관적이고, 공정하게 보도함으로써 진실을 추구할 것을 다짐한다. 또한 공정하고 바르게 평론하며, 사회의 의견을 폭넓게 수용해 다양한 여론 형성에 기여할 것을 결의한다.', '신문윤리강령', '제4조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-5', '명예존중과 사생활 보호', '우리 언론인은 개인 또는 단체의 명예나 신용을 훼손하지 않고 사생활을 침해하지 않을 것을 다짐한다.', '신문윤리강령', '제5조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-6', '반론권과 독자의 권리 존중', '우리 언론인은 개인 또는 단체의 권리를 존중하고 독자에게 반론 등 의견 개진의 기회를 주며 이를 기사에 반영하도록 노력한다.', '신문윤리강령', '제6조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCE-7', '언론인의 품위', '우리 언론인은 사회적 기대에 조응하는 높은 도덕성과 긍지, 품위를 지녀야 한다. 우리는 전문성과 소명의식을 갖추고 언론 본연의 역할에 충실해야 한다. 또한 바르고 고운 언어생활을 이끌어 품격 있는 사회를 구현하는 데 앞장서야 한다.', '신문윤리강령', '제7조', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-P', '신문윤리실천요강 서문', '우리 언론인은 한국신문협회, 한국신문방송편집인협회, 한국기자협회가 채택한 신문윤리강령을 구체적으로 시행하기 위하여 다음과 같은 신문윤리실천요강을 채택하고 이를 준수할 것을 다짐한다. 또한 우리는 이 신문윤리실천요강을 한국신문윤리위원회의 준칙으로 삼을 것을 결의한다.', '신문윤리실천요강', '서문', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('PCP-1-1', '정치권력으로부터의 자유', '정권, 정당 및 정파 등의 정치권력이 언론에 가하는 부당한 압력과 청탁을 거부해야 한다.', '신문윤리실천요강', '제1조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-1-2', '사회·경제 세력으로부터의 독립', '단체, 종파 등 사회 세력이나 기업 등 경제 세력의 부당한 압력, 또는 금전적 유혹이나 청탁을 거부해야 한다.', '신문윤리실천요강', '제1조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-1-3', '사회적 책임', '개인의 권리 보호에 최선을 다하며, 다양한 여론형성과 공공복지 향상을 위하여 사회의 공공문제를 적극적으로 다뤄야 한다.', '신문윤리실천요강', '제1조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-1-4', '차별과 편견 금지', '지역, 계층, 성별, 인종, 종교 간 갈등이나 혐오를 부추기는 보도를 해서는 안 되며, 이에 근거해 개인이나 단체를 차별해서도 안 된다.', '신문윤리실천요강', '제1조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-1-5', '사회적 약자 보호', '장애인 ‧ 노약자 ‧ 성 소수자 등 사회적 약자의 권리 보호에 적극 나서야 하며, 이들에 대해 편견을 갖지 말아야 한다.', '신문윤리실천요강', '제1조 ⑤', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-2-1', '신분 사칭·위장 금지', '신분을 위장하거나 사칭하여 취재해서는 안 된다.', '신문윤리실천요강', '제2조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-2-2', '자료 무단 이용 금지', '문서, 자료, 사진, 영상, 그림, 음악, 인터넷 게시물과 댓글 등의 콘텐츠는 공익을 위해 불가피하지 않은 한 소유주나 관리자의 승인 없이 검색하거나 사용해서는 안 된다.', '신문윤리실천요강', '제2조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-2-3', '재난 및 사고 취재', '재난이나 사고를 취재할 때 인간의 존엄성을 침해하거나 피해자의 치료를 방해해서는 안 되며, 희생자와 피해자 및 그 가족에게 예의를 갖춰야 한다. 재난 등의 수습 및 구조 활동에 지장을 초래해서도 안 된다.', '신문윤리실천요강', '제2조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-2-4', '전화 및 디지털 기기 활용 취재', '취재원과 대면하지 않고 전화나 디지털 기기 등으로 취재할 때 신분을 밝혀야 하며, 상대방에게 예의를 갖춰야 한다.', '신문윤리실천요강', '제2조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-2-5', '도청 및 비밀촬영 금지', '전화 도청이나 비밀촬영 등의 방법으로 취재해서는 안 된다.', '신문윤리실천요강', '제2조 ⑤', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-2-6', '부당한 금전 제공 금지', '금전을 제공하는 등 비윤리적 방법으로 취재하거나 자료를 취득해서는 안 된다.', '신문윤리실천요강', '제2조 ⑥', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-1', '보도기사의 사실과 의견 구분', '보도기사는 사실과 의견을 명확히 구분하여 작성해야 한다. 또한 편견이나 이기적 동기로 보도기사를 고르거나 작성해서는 안 된다.', '신문윤리실천요강', '제3조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-2', '공정보도', '경합 중인 사안을 보도할 때 한 쪽의 주장을 편파적으로 보도하지 않는다. 여론조사 등을 바탕으로 보도할 때는 조사의 신뢰성을 확인할 수 있는 근거를 분명히 밝혀야 하며, 통계를 왜곡해서는 안 된다.', '신문윤리실천요강', '제3조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-3', '반론의 기회', '보도기사에 개인이나 단체를 비판하거나 비방하는 내용이 포함될 때는 상대방에게 해명의 기회를 주고 그 내용을 반영해야 한다.', '신문윤리실천요강', '제3조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-4', '미확인보도 명시 원칙', '출처가 분명하지 않거나 확인되지 않은 사실을 부득이 보도할 때는 그 사유를 분명히 밝혀야 한다.', '신문윤리실천요강', '제3조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-5', '보도자료 검증', '취재원이 제공하는 구두발표와 보도자료는 사실 검증을 거쳐 보도하는 것을 원칙으로 한다.', '신문윤리실천요강', '제3조 ⑤', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-6', '선정보도 금지', '범죄 ‧ 폭력 ‧ 동물학대 등 위법적이거나 비윤리적 행위를 보도할 때 선정적이거나 자극적인 표현을 사용해서는 안 되며 저속하게 다뤄서도 안 된다.', '신문윤리실천요강', '제3조 ⑥', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-7', '재난보도의 신중', '재난이나 대형 사건 등을 보도할 때 흥미 위주의 보도를 지양하고, 자극적이거나 불필요한 공포심을 일으킬 수 있는 표현을 사용하지 않는다. 재난 및 사고의 피해자, 희생자 및 그 가족의 명예나 사생활 등 인권을 침해하는 일이 없도록 각별히 유의해야 한다.', '신문윤리실천요강', '제3조 ⑦', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-8', '자살보도의 주의', '자살보도는 사회에 미치는 영향을 고려하여 신중해야 한다. 자살의 원인과 방법 등을 구체적으로 묘사하여 대중의 호기심을 자극하는 보도를 해서는 안 된다. 특히 표제에는 ''자살''이라는 표현을 삼간다.', '신문윤리실천요강', '제3조 ⑧', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-9', '피의사실 보도', '경찰이나 검찰 등 수사기관이 제공하는 피의사실은 진실 여부를 확인하기 위해 노력해야 한다. 또한 피의자 측에게 해명의 기회를 주기 위해 최선을 다해야 한다.', '신문윤리실천요강', '제3조 ⑨', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-3-10', '표준어 사용', '보도기사를 작성할 때는 표준어 사용을 원칙으로 하며, 저급한 비속어 사용 등으로 독자에게 불쾌감을 주지 않도록 한다.', '신문윤리실천요강', '제3조 ⑩', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-4-1', '재판 부당 영향 금지', '재판에 부당한 영향을 끼치는 취재 ‧ 보도 ‧ 평론을 해서는 안 된다.', '신문윤리실천요강', '제4조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-4-2', '판결문 등의 사전보도 금지', '판결문, 결정문 및 기타 사법문서를 판결이나 결정 전에 보도 ‧ 논평해서는 안 된다. 다만 관련 취재원이 사법문서에 포함된 내용을 제공할 때는 예외로 한다.', '신문윤리실천요강', '제4조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-5-1', '취재원 보호', '취재원의 안전이 위태롭거나 부당하게 불이익을 받을 위험이 있다면 그의 신원을 밝혀서는 안 된다.', '신문윤리실천요강', '제5조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-5-2', '취재원 명시와 익명 조건', '보도기사를 작성할 때는 취재원을 원칙적으로 익명이나 가명으로 표현해서는 안 된다. 다만 공익을 위해 부득이하거나 보도 가치가 우선하는 경우 취재원의 익명 요청을 받아들일 수 있지만, 소속 기관과 일반적 지위를 밝히도록 노력해야 한다.', '신문윤리실천요강', '제5조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-5-3', '제3자 비방과 익명보도 금지', '취재원이 제공한 불특정 출처나 일방적 주장에 근거하여 제3자를 비판, 비방, 공격하는 경우 익명 요청을 원칙적으로 받아들여서는 안 된다.', '신문윤리실천요강', '제5조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-5-4', '취재원과의 비보도 약속', '취재원의 신원이나 내용의 비보도 요청에 동의했을 때는 공익을 위해 불가피하지 않은 한 보도해서는 안 된다.', '신문윤리실천요강', '제5조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-6-1', '보도유예 시한 연장 금지', '자의적인 협의로 보도유예 시한을 정하거나 연장해서는 안 된다.', '신문윤리실천요강', '제6조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-6-2', '보도유예 시한의 효력 상실', '보도유예 시한은 이를 정한 목적에 위배되는 사정이 발생할 경우 효력을 상실한다.', '신문윤리실천요강', '제6조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-7-1', '피의자 및 피고인의 명예 존중', '형사사건의 피의자 및 피고인은 무죄로 추정된다는 점에 유의하여 그의 명예와 인격권을 존중해야 한다.', '신문윤리실천요강', '제7조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-7-2', '피의자·피고인·참고인 등 촬영 신중', '형사사건의 피의자, 피고인, 참고인 및 증인을 촬영하거나 사진 또는 영상을 보도할 때는 인격권을 존중하되 최대한 공익을 고려해야 한다.', '신문윤리실천요강', '제7조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-7-3', '범죄와 무관한 가족 보호', '범죄사건을 보도할 때는 범죄와 관련이 없는 가족의 신원을 밝혀서는 안 된다.', '신문윤리실천요강', '제7조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-7-4', '성범죄 등의 2차 피해 방지', '성범죄 사건 등을 보도할 때는 피해자와 가족, 주변인에게 2차 피해가 발생하지 않도록 유의해야 한다.', '신문윤리실천요강', '제7조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-7-5', '미성년 피의자 신원 보호', '피의자 또는 피고인이 미성년(18세 이하)일 경우 이름 ‧ 사진 등의 신원을 밝혀서는 안 된다.', '신문윤리실천요강', '제7조 ⑤', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-8-1', '통신기사의 출처 명시', '통신기사를 전재할 때는 출처를 밝혀야 하며, 사소한 내용을 변경하여 자사 기사로 바꿔서는 안 된다.', '신문윤리실천요강', '제8조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-8-2', '타 언론사 보도 등의 표절 금지', '타 언론사의 보도와 논평을 표절해서는 안 되며, 출처를 명시하지 않고 실체적 내용을 인용해서도 안 된다. 다만 출처가 여럿일 경우 이를 포괄적으로 명시할 수 있다.', '신문윤리실천요강', '제8조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-8-3', '출판물 등의 표절 금지', '정기간행물이나 출판물 등의 내용을 표절해서는 안 되며, 발췌 인용할 때는 출처를 밝혀야 한다.', '신문윤리실천요강', '제8조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-8-4', '사진, 영상 등의 저작권 보호', '개인이나 단체의 사진, 영상, 그림, 음악, 인터넷 게시물과 댓글 등의 저작권을 보호해야 하며, 보도나 평론에 사용할 때는 출처를 밝혀야 한다.', '신문윤리실천요강', '제8조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-9-1', '사설의 정론성', '사설은 소속 언론사의 정론적 입장을 대변해야 하며, 특히 언론사의 상업적 이익이나 특정 정당 ‧ 단체 ‧ 종파의 이권을 대변해서는 안 된다.', '신문윤리실천요강', '제9조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-9-2', '평론의 자유', '사설 등 평론은 실정법을 위반하지 않는 한 특정 정당 또는 특정인에 대한 지지 또는 반대 등 정치적 입장을 자유롭게 표현할 수 있다.', '신문윤리실천요강', '제9조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-1', '제목의 원칙', '제목은 기사의 요약된 내용이나 핵심 내용을 대표해야 하며, 기사 내용을 과장하거나 왜곡해서는 안 된다.', '신문윤리실천요강', '제10조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-2', '편집 변경 금지', '사내외의 부당한 요구에 따라 기사를 없애거나 기사의 크기 ‧ 배치 등을 바꿔서는 안 된다.', '신문윤리실천요강', '제10조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-3', '기고문 변경 금지', '사외 기고문은 기고자의 동의 없이 실체적 내용을 변경해서는 안 된다.', '신문윤리실천요강', '제10조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-4', '기사 정정', '보도기사의 오류를 발견하거나 정정 요구를 받았을 때는 확인을 거쳐 그 내용을 신속하고 뚜렷하게 게재해야 한다.', '신문윤리실천요강', '제10조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-5', '관련사진 게재', '보도사진은 기사의 실체적 내용과 직접적으로 관련돼 있어야 한다. 다만 부득이 기사와 간접적으로 관련된 사진을 사용할 때는 그 사실을 밝혀야 한다.', '신문윤리실천요강', '제10조 ⑤', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-6', '사진 및 영상 조작 금지', '보도사진이나 영상의 실체적 내용을 삭제, 첨가, 변형하는 등 조작해서는 안 된다. 다만 편집의 기술적 편의를 위해 부득이한 경우 최소한의 조작기법을 사용할 수 있으나 그 사실을 밝혀야 한다.', '신문윤리실천요강', '제10조 ⑥', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-7', '기사와 광고의 구분', '독자들이 기사와 광고를 명확하게 구분할 수 있도록 편집해야 한다. 광고를 기사와 같은 지면이나 공간에 배치할 때는 독자가 명백하게 광고로 인식할 수 있도록 표시해야 한다.', '신문윤리실천요강', '제10조 ⑦', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-8', '이용자의 권리 보호', '홈페이지 운영자는 이용자들의 참여와 편익을 최대한 보장하고, 콘텐츠에 오류가 없도록 수시로 점검, 관리하며, 특히 청소년이 유해물에 노출되지 않도록 유의해야 한다.', '신문윤리실천요강', '제10조 ⑧', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-10-9', '부당한 재전송 금지', '부당한 목적으로 제목과 기사의 일부를 바꾸는 등의 방법으로 같거나 비슷한 기사를 반복적으로 게재해서는 안 된다.', '신문윤리실천요강', '제10조 ⑨', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-11-1', '명예·신용 훼손 금지', '오보, 부정확한 보도, 왜곡보도, 공익과 무관한 보도, 저속한 표현 등으로 개인이나 단체의 인격권이나 명예 ‧ 신용을 훼손해서는 안 된다.', '신문윤리실천요강', '제11조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-11-2', '사자의 명예 존중', '보도와 평론을 할 때 사자의 명예를 부당하게 훼손해서는 안 된다.', '신문윤리실천요강', '제11조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-12-1', '사생활 침해 금지', '개인의 사생활 영역에 허락 없이 침입해서는 안 된다.', '신문윤리실천요강', '제12조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-12-2', '개인정보 무단 검색 등 금지', '디지털 기기 등에 입력된 개인정보를 소유주나 관리자의 승인 없이 검색하거나 사용해서는 안 된다.', '신문윤리실천요강', '제12조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-12-3', '사생활 등의 촬영 및 보도 금지', '개인의 사생활, 사유물을 동의 없이 촬영하거나 취재, 보도해서는 안 된다. 다만 공인의 경우 예외로 할 수 있다.', '신문윤리실천요강', '제12조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-12-4', '공인의 사생활 보도', '공익을 위해 공인의 사생활을 보도 ‧ 평론하는 때에도 절제를 잃지 않도록 경계해야 한다.', '신문윤리실천요강', '제12조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-13-1', '청소년과 어린이 취재 보도', '부모나 보호자의 승인 없이 청소년(19세 미만)이나 어린이(13세 미만)와 접촉하거나 촬영 ‧ 보도해서는 안 된다.', '신문윤리실천요강', '제13조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-13-2', '범죄 보도와 청소년, 어린이 보호', '청소년이나 어린이, 그의 가족이 범죄에 연루된 경우 그 청소년이나 어린이의 신원을 밝혀서는 안 된다.', '신문윤리실천요강', '제13조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-13-3', '유해환경으로부터의 보호', '폭력 ‧ 음란 ‧ 약물사용 ‧ 도박 등을 미화하거나 지나치게 상세히 보도하여 청소년과 어린이가 유해환경에 노출되지 않도록 경계해야 한다.', '신문윤리실천요강', '제13조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-13-4', '유괴·납치 보도제한 협조', '어린이나 청소년이 유괴 ‧ 납치된 경우 안전을 위해 수사기관 등의 보도제한 요청에 협조해야 한다.', '신문윤리실천요강', '제13조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-14-1', '소유 주식 등에 관한 보도 제한', '언론인 본인, 친인척 또는 이해 관계자가 소유한 주식 ‧ 전자화폐 등의 거래에 영향을 미칠 수 있는 보도를 해서는 안 된다.', '신문윤리실천요강', '제14조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-14-2', '주식·부동산 등의 부당 거래 금지', '취재 및 기타 언론활동에서 얻은 정보를 주식 ‧ 부동산 거래 또는 사사로운 이익을 위해 이용해서는 안 된다.', '신문윤리실천요강', '제14조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-15-1', '금품수수 및 향응, 청탁 금지', '취재 ‧ 보도 ‧ 평론 ‧ 편집과 관련하여 이해 당사자로부터 금품, 향응 등 유무형의 경제적 이익을 취해서는 안 되며, 이를 요구해서도 안 된다.', '신문윤리실천요강', '제15조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-15-2', '부당한 집단 영향력 행사 금지', '공동취재나 친목 또는 직업적 공동이익을 위한 목적 이외에 단체를 구성하거나 활동해서는 안 되며, 취재원에 집단적 영향력을 행사해서도 안 된다.', '신문윤리실천요강', '제15조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-15-3', '광고·판매 등 영업행위 금지', '언론사는 언론인에게 취재 ‧ 편집 등에 영향을 미칠 수 있는 부당한 광고 ‧ 판매 등의 영업행위를 요구해서는 안 되며, 언론인도 그런 요구를 받아들여서는 안 된다.', '신문윤리실천요강', '제15조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-16-1', '국가 안전 등', '국가의 안전 보장, 사회질서 유지, 공공복리를 위해 부득이한 경우', '신문윤리실천요강', '제16조 ①', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-16-2', '공중 안녕', '공중의 보건과 안전, 환경 보존을 위해 부득이한 경우', '신문윤리실천요강', '제16조 ②', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-16-3', '범죄의 폭로', '반사회적 범죄 또는 중대한 비윤리적 행위를 방지하기 위해 부득이한 경우', '신문윤리실천요강', '제16조 ③', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PCP-16-4', '공중의 오도 방지', '개인이나 단체의 주장 또는 행동으로 공중이 오도되는 것을 막기 위해 부득이한 경우', '신문윤리실천요강', '제16조 ④', 2, NULL, NULL, 'general', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-P', '인권보도준칙 전문', '언론은 모든 사람이 사람답게 사는 세상을 위해 인류 보편적 가치인 인권의 증진을 목표로 삼는다. 언론은 이를 위해 인권문제를 적극 발굴·보도하여 사회적 의제로 확산시키고 인권보장을 위한 제도가 정착되도록 여론형성에 앞장선다. 언론은 일상적 보도과정에서 인권을 침해하는 내용이 포함되지 않도록 주의를 기울인다. 아울러 ''다름''과 ''차이''가 차별의 이유가 되지 않도록 노력한다. 언론은 인권의 증진이 기본적 사명임을 깊이 인식하여 국민의 인권의식 향상과 인권존중문화 확산에 기여한다. 이에 따라 한국기자협회와 국가인권위원회는 다음과 같이 인권보도준칙을 제정하여 이를 준수하도록 권고한다.', '인권보도준칙', '전문', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('HRG-G1', '국제규범과 헌법의 인권 실현', '언론은 세계인권선언을 비롯한 국제규범과 헌법에서 보장된 인권이 실현되도록 노력한다.', '인권보도준칙', '총강 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G2', '세계인권선언 보편 적용', '언론은 ''모든 사람은 태어날 때부터 자유롭고 존엄하며 평등하다''는 세계인권선언의 정신을 누구에게나 예외없이 적용한다.', '인권보도준칙', '총강 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G3', '표현의 자유와 알권리 보장', '언론은 표현의 자유 등 민주적 공동체 구현에 필수 불가결한 기본권의 신장과 모든 사람의 알권리 보장을 위해 힘쓴다.', '인권보도준칙', '총강 3', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G4', '인권 사각지대 발굴', '언론은 인권 사각지대의 인권 현안을 적극 발굴하여 우리 사회의 인권신장에 앞장선다.', '인권보도준칙', '총강 4', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G5', '사회적 약자·소수자 감시와 제도 촉구', '언론은 사회적 약자나 소수자들의 인권 보장을 위해 그들이 차별과 소외를 받지 않도록 감시하고 제도적 권리 보장을 촉구한다.', '인권보도준칙', '총강 5', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G6', '용어 선택과 표현 주의', '언론은 고정관념이나 사회적 편견 등에 의한 인권침해를 방지하기 위해 용어 선택과 표현에 주의를 기울인다.', '인권보도준칙', '총강 6', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G7', '사진·영상보도의 인권 존중', '언론은 사진과 영상보도에서도 인권을 침해하지 않도록 주의한다.', '인권보도준칙', '총강 7', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G8', '생명권 보장과 자살보도 신중', '언론은 생명권 보장과 생명존중 문화 확산에 기여하고 자살보도에 신중을 기한다.', '인권보도준칙', '총강 8', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G9', '인권교육매체 역할', '언론은 인권교육매체로서 우리 사회의 인권의식 향상과 인권감수성 향상에 기여한다.', '인권보도준칙', '총강 9', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-G10', '오보 인권침해 시 정정', '언론은 오보 등으로 인해 인권을 침해한 경우 솔직하게 인정하고 신속하게 바로잡는다.', '인권보도준칙', '총강 10', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-1', '민주주의·국민주권 훼손 표현 금지', '언론은 민주주의와 국민주권을 훼손하는 표현을 사용하지 않는다.', '인권보도준칙', '제1장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-1a', '권위적 용어·국민 비하 용어 주의', '권위적인 용어와 국민을 낮춰보는 용어 사용에 주의한다.', '인권보도준칙', '제1장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-1b', '권력층 과도 예우 용어 금지', '사회 각 부문의 권력층을 지나치게 예우하는 용어를 사용하지 않는다.', '인권보도준칙', '제1장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-1c', '집회·시위 부정적 묘사 금지', '민주적 기본권인 집회·시위를 부정적으로 묘사하지 않는다.', '인권보도준칙', '제1장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-2', '특정 집단·계층 편향·차별 보도 금지', '언론은 특정 집단이나 계층에 편향되거나 차별적인 보도를 하지 않도록 주의한다.', '인권보도준칙', '제1장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-2a', '정치인 옹호·비하 용어 주의', '특정 정치인(집단)을 옹호하거나 비하하는 용어 사용에 주의한다.', '인권보도준칙', '제1장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-2b', '노사 관계 편파·노동3권 무시 금지', '노사 관계에 대해 편파적인 보도나 헌법 제33조에 보장된 노동3권을 무시하는 표현을 하지 않는다.', '인권보도준칙', '제1장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-2c', '계층 간 갈등 조장·빈부격차 정당화 금지', '계층 간 갈등을 조장하거나 빈부격차를 정당화하고, 기업의 입장에서 사용하는 용어를 일반화하지 않도록 한다.', '인권보도준칙', '제1장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-1-2d', '지역 비하·차별 조장 용어 금지', '특정 지역을 비하하거나 지역 간 차별을 조장하는 용어를 사용하지 않는다.', '인권보도준칙', '제1장 2-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1', '개인 인격권 침해 금지', '언론은 개인의 인격권(명예, 프라이버시권, 초상권, 음성권, 성명권)을 부당하게 침해하지 않는다.', '인권보도준칙', '제2장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1a', '비공인 신상·사생활 공개 시 동의', '''공인''이 아닌 개인의 얼굴, 성명 등 신상 정보와 병명, 가족관계 등 사생활에 속하는 사항을 공개하려면 원칙적으로 당사자의 동의를 받아야 한다.', '인권보도준칙', '제2장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1b', '공인 초상·성명 관련 없으면 미사용', '''공인''의 초상이나 성명, 프라이버시는 보도 내용과 관련이 없으면 사용하지 않는다.', '인권보도준칙', '제2장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1c', '취재 과정 인격권·개인정보 유출 방지', '취재 과정에서 인격권 침해와 개인 정보 유출이 일어나지 않도록 주의한다.', '인권보도준칙', '제2장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1d', '사망자·유가족 인격권 보호', '사망자와 유가족의 인격권을 침해하지 않는다.', '인권보도준칙', '제2장 1-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1e', '자살보도 주의', '자살 예방을 위해 가급적 자살 사건을 보도하지 않으며, 보도가 불가피한 경우에는 자살을 미화·합리화하거나 실행방법을 묘사하지 않는다.', '인권보도준칙', '제2장 1-마', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-1f', '인용·인터뷰 인격권 침해·차별 조장 금지', '인용이나 인터뷰를 이용하여 인격권을 침해하거나 차별을 조장하지 않는다.', '인권보도준칙', '제2장 1-바', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2', '범죄 사건 기본권 보호', '언론은 범죄 사건의 경우 헌법 제27조의 무죄추정의 원칙, 공정한 재판을 받을 권리 등 국민의 기본권을 침해하지 않도록 주의한다.', '인권보도준칙', '제2장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2a', '수사·재판 중 단정적 표현 금지', '수사나 재판 중인 사건을 다룰 때 단정적인 표현을 사용하지 않는다.', '인권보도준칙', '제2장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2b', '피의자·피해자 등 신상 비공개 원칙', '용의자, 피의자, 피고인 및 피해자, 제보자, 고소·고발인의 얼굴, 성명 등 신상 정보는 원칙적으로 밝히지 않는다.', '인권보도준칙', '제2장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2c', '유죄 판결 후에도 신상 공개 신중', '유죄 판결을 받은 경우에도 범죄자의 얼굴, 성명 등 신상 정보 공개에 신중을 기한다.', '인권보도준칙', '제2장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2d', '피해자 2차 피해 방지', '피해자의 2차 피해를 막기 위해 범죄 행위를 자세히 묘사하지 않는다.', '인권보도준칙', '제2장 2-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2e', '성폭행 피해자 익명성·촬영 금지', '성폭행 피해자의 익명성을 보장하고 피해 상황을 설명할 때는 신중을 기해야 하며, 특히 피해자의 상처를 사진이나 영상으로 촬영, 공개하지 않는다.', '인권보도준칙', '제2장 2-마', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2f', '범죄 원인 피해자 탓 금지', '범죄 발생의 원인이 피해자 측에 있는 것처럼 묘사하지 않는다.', '인권보도준칙', '제2장 2-바', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-2-2g', '사회구조적 문제 진단·제도 개선', '사건에 대한 사회구조적인 문제점을 진단하고 인권친화적인 방향으로 정책 변경과 제도 개선이 이뤄지도록 노력한다.', '인권보도준칙', '제2장 2-사', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1', '장애인 자존감·존엄성·인격권 무시 보도 금지', '언론은 장애인이 자존감과 존엄성, 인격권을 무시당한다고 느낄 수 있는 보도를 하지 않는다.', '인권보도준칙', '제3장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1a', '장애인 비하·차별 표현 주의', '장애인을 비하하거나 차별하는 표현에 주의한다.', '인권보도준칙', '제3장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1b', '부정적 관용구 금지', '통상적으로 쓰이는 말 중 장애인에 대해 부정적 뉘앙스를 담고 있는 관용구를 사용하지 않는다.', '인권보도준칙', '제3장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1c', '장애 유형·상태 과도 부각 금지', '장애 유형과 장애 상태를 지나치게 부각하지 않는다.', '인권보도준칙', '제3장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1d', '수동적 존재 묘사 금지', '장애인을 보장구에 의지하여 살아가는 수동적 존재로 묘사하지 않는다.', '인권보도준칙', '제3장 1-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1e', '동정·이질적 존재 묘사 금지', '동정 어린 시각이나 사회의 이질적 존재라는 인상을 주지 않도록 한다.', '인권보도준칙', '제3장 1-마', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-1f', '장애를 질병으로 묘사 금지', '장애를 질병으로 묘사하거나 연상시킬 수 있는 표현을 사용하지 않는다.', '인권보도준칙', '제3장 1-바', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-2', '장애인 차별 해소 적극 보도', '언론은 장애인에 대한 차별을 해소하는 데 적극 나선다.', '인권보도준칙', '제3장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-2a', '고정관념·편견 강화 표현 금지', '장애에 대한 잘못된 고정관념과 편견을 강화할 수 있는 표현을 사용하지 않는다.', '인권보도준칙', '제3장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-2b', '미담 보도 대상화·도구화 금지', '''미담 보도''의 경우 장애인을 대상화하거나 도구화하지 않는다.', '인권보도준칙', '제3장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-2c', '장애인 인터뷰 시 당사자 입장 고려', '장애인을 인터뷰하거나 언론에 노출할 경우 반드시 당사자의 입장을 고려한다.', '인권보도준칙', '제3장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-3-2d', '제도·인식 개선 노력', '장애인을 위한 제도 개선과 사회의 인식을 개선하기 위해 항상 노력한다.', '인권보도준칙', '제3장 2-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-1', '성차별적 표현 금지', '언론은 성별과 성 역할에 대한 고정관념을 강화하는 성차별적 표현을 사용하지 않는다.', '인권보도준칙', '제4장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-1a', '양성 특성 과도 부각·성별 불필요 강조 금지', '양성의 특성을 지나치게 부각하거나 성별을 불필요하게 강조하지 않는다.', '인권보도준칙', '제4장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-1b', '가부장적 표현 금지', '가부장적 표현이 드러나지 않도록 주의한다.', '인권보도준칙', '제4장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-1c', '성별 고정관념 표현 금지', '성별에 대한 고정관념을 야기하는 표현을 사용하지 않는다.', '인권보도준칙', '제4장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-1d', '성 역할 이분법 고정화 금지', '양성의 성 역할을 이분법적으로 고정화하여 표현하지 않는다.', '인권보도준칙', '제4장 1-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-2', '성적 대상화·상품화 보도 금지', '언론은 사람을 성적으로 대상화하거나 성을 상품화하는 보도를 하지 않는다.', '인권보도준칙', '제4장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-2a', '성적·신체적 특성 과도 강조 금지', '성적 또는 신체적 특성을 과도하게 강조하지 않는다.', '인권보도준칙', '제4장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-4-2b', '특정 신체 부위 부각 금지', '사람의 특정 신체 부위를 부각하는 사진이나 영상을 사용하지 않는다.', '인권보도준칙', '제4장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-1', '다양한 문화 존중', '언론은 다양한 문화를 존중하고 여러 민족이 더불어 살아가는 사회가 되도록 노력한다.', '인권보도준칙', '제5장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-1a', '출신 무관 인권 존중', '출신 국가, 민족, 인종, 피부색, 체류 자격, 국적 유무와 관계없이 모든 사람의 인권을 존중하고 증진하도록 힘쓴다.', '인권보도준칙', '제5장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-1b', '특정 국가·민족·인종 차별·비하 표현 금지', '특정 국가나 민족, 인종을 차별하거나 비하하는 표현을 사용하지 않는다.', '인권보도준칙', '제5장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-1c', '이주민 동화·한국 가치 강요 보도 자제', '이주민이 한국문화에 동화·흡수되도록 유도하거나 한국의 문화와 가치를 강요하는 보도를 자제한다.', '인권보도준칙', '제5장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-1d', '이주민 구경거리·동정 대상 묘사 금지', '이주민을 한국의 관점이나 기준으로 평가해 구경거리로 만들거나 동정을 받아야 할 대상으로 묘사하지 않는다.', '인권보도준칙', '제5장 1-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-2', '이주민 부정적 이미지 조장·차별 금지', '언론은 이주민에 대해 희박한 근거나 부정확한 추측으로 부정적인 이미지를 조장하거나 차별하지 않는다.', '인권보도준칙', '제5장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-2a', '미허가 체류 외국인 ''범죄자'' 이미지 금지', '체류 허가를 받지 않은 외국인에게 ''범죄자''라는 부정적 이미지를 덧씌울 수 있는 용어 사용에 주의한다.', '인권보도준칙', '제5장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-2b', '이주노동자 잠재적 범죄자·전염병 원인 표현 금지', '이주노동자 등을 잠재적 범죄자 또는 전염병 원인 제공자 등으로 몰아갈 수 있는 표현을 사용하지 않는다.', '인권보도준칙', '제5장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-5-2c', '이주노동자 동정·웃음거리 묘사 금지', '이주노동자를 동정의 대상으로 삼거나 어눌한 한국어 표현 등에 주목해 웃음거리로 묘사하지 않는다.', '인권보도준칙', '제5장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-1', '노인 문제 제도적·종합적 접근', '언론은 노인 문제를 제도적이고 종합적인 관점으로 접근한다.', '인권보도준칙', '제6장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-1a', '의존적 존재 부각·부정적 이미지 금지', '노인을 지나치게 의존적 존재로 부각하지 않으며, 부정적 이미지를 조장하지 않는다.', '인권보도준칙', '제6장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-1b', '노인 문제 개인 문제화 금지·사회적 해법 제시', '노인의 경제적 어려움, 학대, 범죄, 자살 등을 개인 문제로 다루지 않고 사회적, 정책적 해법의 필요성을 제시한다.', '인권보도준칙', '제6장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-2', '노인 독립·사회참여·존엄성 존중', '언론은 노인의 독립과 사회참여, 자아실현, 존엄성을 존중한다.', '인권보도준칙', '제6장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-2a', '연령 차별 금지', '연령을 이유로 노동시장 등 사회생활에서 차별받지 않도록 보도한다.', '인권보도준칙', '제6장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-2b', '시설 노인 등 인권 관심', '노인 인권 침해, 특히 시설 생활 노인 등의 인권에 지속적으로 관심을 갖고 살펴본다.', '인권보도준칙', '제6장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-6-2c', '노인 결혼·이혼 선정적 접근 금지', '노인의 결혼과 이혼 등에 대해 선정적으로 접근하지 않는다.', '인권보도준칙', '제6장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-1', '동등한 인격체 인식', '언론은 어린이와 청소년을 어른과 동등한 인격체로 인식하는 자세를 갖는다.', '인권보도준칙', '제7장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-1a', '나이 이유 권리 무시 금지', '어린이와 청소년이 어리다는 이유로 그들의 권리를 무시하지 않는다.', '인권보도준칙', '제7장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-1b', '따돌림·학교폭력 등 입장 고려', '따돌림, 학교폭력, 체벌, 인터넷 중독 등을 다룰 때 어린이와 청소년의 입장을 고려한다.', '인권보도준칙', '제7장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-2', '안전 배려', '언론은 어린이와 청소년의 안전에 미칠 영향에 대해 세심하게 배려한다.', '인권보도준칙', '제7장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-2a', '선정적·폭력적 묘사 자제', '어린이와 청소년에게 충격을 줄 우려가 있는 선정적·폭력적 묘사를 자제한다.', '인권보도준칙', '제7장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-2b', '후원받는 어린이 신상 비공개', '주변의 도움이나 후원을 받는 경우 얼굴, 성명 등 신상 정보가 공개되지 않도록 주의한다.', '인권보도준칙', '제7장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-2c', '범죄 재연 시 아동 미출연', '범죄 사건을 재연할 경우 아동을 출연시키지 않는다.', '인권보도준칙', '제7장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-7-2d', '피해자 익명성·시각자료 미공개', '피해자의 2차 피해를 막기 위해 익명성을 보장하고 피해상황과 관련한 사진과 영상은 원칙적으로 공개하지 않는다.', '인권보도준칙', '제7장 2-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-1', '호기심·배척 접근 금지', '언론은 성적 소수자에 대해 호기심이나 배척의 시선으로 접근하지 않는다.', '인권보도준칙', '제8장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-1a', '비하 표현·왜곡·잘못된 용어 금지', '성적 소수자를 비하하는 표현이나 진실을 왜곡하는 내용, ''성적 취향'' 등 잘못된 개념의 용어 사용에 주의한다.', '인권보도준칙', '제8장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-1b', '타락 뉘앙스 금지', '성적 소수자가 잘못되고 타락한 것이라는 뉘앙스를 담지 않는다.', '인권보도준칙', '제8장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-1c', '불필요한 성적 지향·정체성 공개 금지', '반드시 필요하지 않을 경우 성적 지향이나 성 정체성을 밝히지 않는다.', '인권보도준칙', '제8장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-1d', '혐오 표현 금지', '성적 소수자에 대해 혐오에 가까운 표현을 사용하지 않는다.', '인권보도준칙', '제8장 1-라', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-2', '특정 질환·사회병리 연결 금지', '언론은 성적 소수자를 특정 질환이나 사회병리 현상과 연결 짓지 않는다.', '인권보도준칙', '제8장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-2a', '정신 질환·치료 가능 질병 묘사 금지', '성적 소수자의 성 정체성을 정신 질환이나 치료 가능한 질병으로 묘사하는 표현에 주의한다.', '인권보도준칙', '제8장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-8-2b', '에이즈·성매매·마약 연결 금지', '에이즈 등 특정 질환이나 성매매, 마약 등 사회병리 현상과 연결 짓지 않는다.', '인권보도준칙', '제8장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-1', '사회 구성원 관점 접근', '언론은 북한이탈주민을 우리 사회의 구성원이라는 관점으로 접근한다.', '인권보도준칙', '제9장 1', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-1a', '동의 없는 신상 비공개', '본인과 가족의 안전을 위해 동의가 없는 한 성명, 출신 등 신상정보가 공개되지 않도록 주의한다.', '인권보도준칙', '제9장 1-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-1b', '수동적·자립심 부족 묘사 금지', '북한이탈주민을 항상 도움이 필요한 수동적이고 자립심이 부족한 사람으로 묘사하지 않는다.', '인권보도준칙', '제9장 1-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-1c', '부적응 사례 제도적 관점', '사회 부적응 등 부정적 사례를 보도할 경우, 개인적인 문제가 아니라 제도적 관점에서 살펴본다.', '인권보도준칙', '제9장 1-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-2', '통일 관점에서 북한 주민 바라봄', '언론은 통일이라는 장기적이고 성숙한 관점으로 북한 주민을 바라본다.', '인권보도준칙', '제9장 2', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-2a', '경제·문화 비하·희화화 금지', '북한 주민의 경제 상황이나 외부와 고립되어 형성된 독특한 문화를 비하하거나 희화화하지 않는다.', '인권보도준칙', '제9장 2-가', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-2b', '도발 시 북한 주민 적대감 금지', '북한의 도발이나 긴장 유발 시 북한의 잘못은 지적하되 북한 주민들에 대해서는 적대감을 표출하지 않는다.', '인권보도준칙', '제9장 2-나', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HRG-9-2c', '안전 보장 시에만 식별 가능 자료 사용', '안전이 보장될 때에만 식별이 가능한 사진과 영상을 사용한다.', '인권보도준칙', '제9장 2-다', 3, '도메인 특화 규범 (인권 보도)', NULL, 'human_rights', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-P', '자살보도 윤리강령 서문', '죽음의 방식은 한 개인의 사적 영역에 속하며 언론은 이를 존중해야 합니다. 따라서 언론은 자살에 대한 보도에서 매우 신중해야 합니다. 언론의 자살 보도 방식은 자살에 영향을 미칩니다. 자살 의도를 가진 사람이 모두 이를 실행에 옮기는 것이 아닙니다. 언론의 자살 보도가 그 계기가 될 수 있습니다. 또한 자살 보도는 사람들이 삶의 어려움을 극복하기 위한 한 방법으로 자살을 고려하게 만들 수도 있습니다. 자살이 언론의 정당한 보도 대상이지만, 언론은 자살 보도가 청소년을 비롯한 공중에게 미치는 영향에 대해 충분한 예민성과 책임감을 가져야 합니다. 우리는 언론인들이 자살에 대한 보도에서 아래의 준칙을 지켜주실 것을 권고합니다.', '자살보도 윤리강령', '서문', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('SRE-1', '자살보도 자제 및 신원 비공개', '언론은 공공의 정당한 관심의 대상이 되는 사건이 아닌 경우에는 자살에 대한 보도를 자제해야 한다. 자살 사건에 대한 보도에서 사회적으로 중요한 인물의 자살과 같은 예외적인 경우를 제외하고는 자살자의 이름과 사진을 공개해서는 안되며, 주변 상황에 대한 보도를 자제해야 한다.', '자살보도 윤리강령', '제1조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-2', '자살 영웅화·미화·유용한 방법 묘사 금지', '언론은 자살을 영웅시 혹은 미화하거나 삶의 문제를 해결하는데 쉽고 유용한 방법으로 묘사해서는 안된다.', '자살보도 윤리강령', '제2조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-3', '자살 장소·방법·경위 묘사 금지', '언론은 자살 장소 및 자살 방법, 자살까지의 자세한 경위를 묘사해서는 안된다. 단, 사회적으로 중요한 인물의 자살 등과 같이 공공의 정당한 관심의 대상이 될 수 있는 경우와 그러한 묘사가 사건을 이해하는데 반드시 필요한 경우는 예외로 한다.', '자살보도 윤리강령', '제3조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-4', '자살 동기 단정 금지', '언론은 자살 동기에 대한 단편적이고 단정적인 판단을 바탕으로 이를 보도해서는 안된다.', '자살보도 윤리강령', '제4조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-5', '통계·자료의 정확한 인용', '언론이 자살 현상에 대해 보도할 때에는 확실한 자료와 출처를 인용하며, 통계 수치는 주의 깊고 정확하게 해석해야 하고 충분한 근거 없이 일반화해서는 안된다.', '자살보도 윤리강령', '제5조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-6', '저널리즘 원칙에 입각한 보도', '언론은 자살 사건의 보도 여부, 편집, 보도방식과 보도 내용은 유일하게 저널리즘의 기본 원칙에 입각해서 결정하며, 흥미를 유발하거나 속보 및 특종 경쟁의 수단으로 자살 사건을 다루어서는 안된다.', '자살보도 윤리강령', '제6조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-7', '사생활 보호', '언론은 자살 보도에서 자살자와 그 유족의 사생활이 침해되지 않도록 주의를 기울여야 한다.', '자살보도 윤리강령', '제7조', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A1', '영웅적 행위·낭만적 해결책 포장 금지', '자살을 영웅적 행위나 낭만적 해결책처럼 포장하기', '자살보도 윤리강령', '실천요강-피해라 1', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A2', '자살 방법 소개·상세 설명 금지', '(새로운) 자살 방법을 소개하고 세세하게 설명하기', '자살보도 윤리강령', '실천요강-피해라 2', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A3', '일반화·원인 단순화 금지', '작은 사실에 근거하여 일반화하거나, 자살의 원인을 단순화하기', '자살보도 윤리강령', '실천요강-피해라 3', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A4', '예고·이유 없이 일어났다는 서술 금지', '자살이 아무런 예고나 이유 없이 일어났다고 서술하기', '자살보도 윤리강령', '실천요강-피해라 4', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A5', '정신건강·약물중독 문제 은폐 금지', '자살한 사람의 매력이나 명성에 누가 될까봐 정신건강 상태나 약물중독과 같은 문제를 쉬쉬하기', '자살보도 윤리강령', '실천요강-피해라 5', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A6', '헤드라인 ''자살'' 사용·사인 공개 금지', '''자살''이란 용어를 헤드라인에 쓰거나, 사인(死因)을 자살로 밝히기', '자살보도 윤리강령', '실천요강-피해라 6', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A7', '자살한 사람의 사진 게재 금지', '자살한 사람의 사진 넣기', '자살보도 윤리강령', '실천요강-피해라 7', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-A8', '유명인 자살 주요기사 게재 금지', '유명인의 자살을 주요기사로 싣기', '자살보도 윤리강령', '실천요강-피해라 8', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D1', '자살률 최근 경향 제공', '자살률의 최근 경향', '자살보도 윤리강령', '실천요강-넣어라 1', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D2', '치료·상담 발전 양상 제공', '최근의 치료 및 상담의 발전 양상', '자살보도 윤리강령', '실천요강-넣어라 2', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D3', '위기 극복 사례 제공', '치료 및 상담을 받고 자살위기에서 벗어난 사람들의 사례', '자살보도 윤리강령', '실천요강-넣어라 3', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D4', '절망 극복 사례 제공', '자살하지 않고도 절망에서 일어선 사람들의 사례', '자살보도 윤리강령', '실천요강-넣어라 4', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D5', '자살 신화(잘못된 상식) 교정 정보 제공', '자살의 신화(잘못된 상식)', '자살보도 윤리강령', '실천요강-넣어라 5', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D6', '자살 징후 소개', '자살 징후들 소개', '자살보도 윤리강령', '실천요강-넣어라 6', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SRE-D7', '위기자 도움 방법 제공', '자살위기에 처한 다른 사람을 도울 수 있는 방법', '자살보도 윤리강령', '실천요강-넣어라 7', 3, '도메인 특화 규범 (자살 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-P', '군 취재·보도 기준 서문', '이 기준은 북한의 군사도발과 외부세력 침입으로 군사작전이 전개되는 등 국가안보상의 중대한 위기가 발생했을 때 언론과 군이 갈등 소지를 방지하고 양측의 원활한 협조 필요성에 대한 공감대에 바탕을 둔 것이다. 국민의 알 권리를 위한 언론의 보도 행위와 군의 국가보위 및 국민 보호 임무가 조화로운 균형을 이루어야 한다. 군은 국민 알권리 충족을 위해 신속하고 충분한 정보를 제공하고 언론은 국가안보와 작전에 임하는 장병의 안전을 고려하여 신중하게 보도해야 한다. 각 언론사는 군 작전지역 등 위험지역 취재 시 군 당국과 사전에 협의하고 군은 취재진의 안전한 취재활동 보장을 위해 최선을 다해야 한다.', '군 취재·보도 기준', '서문', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('MRG-1', '목적', '이 기준은 북한의 군사도발과 외부세력 침입 등에 의해 군 비상상황이 발생하였을 경우 군의 작전을 보장하면서 정확하고 신속한 취재 보도에 대한 기본적인 방향과 실천요강을 제공하는데 있다.', '군 취재·보도 기준', '제1조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-2', '적용범위', '이 기준은 군은 물론 한국기자협회 소속 회원사와 회원, 작전지역 취재에 참여하는 모든 매체에게 적용된다. 다만, 한국에서 활동하는 외신에 대해서는 한국기자협회가 외신기자협회에 이 기준을 준수하도록 협조를 구한다.', '군 취재·보도 기준', '제2조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-3', '용어의 정의', '이 기준에서 ''국가안보위기''란 북한 및 외부세력이 대한민국의 주권과 국민의 생존에 중대한 위협을 가하는 도발행위를 감행하여 군이 작전을 수행하는 경우를 말한다.', '군 취재·보도 기준', '제3조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-4', '취재지원 원칙', '군은 비상상황과 관련한 정보가 ''사실에 입각하여, 신속하고, 정확하게'' 국민들에게 전달되도록 언론의 취재 및 보도 활동을 적극적으로 지원한다.', '군 취재·보도 기준', '제4조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-5', '신변안전 대책', '작전지역 부대는 취재 보도진에 대한 신변안전 대책을 강구한다.', '군 취재·보도 기준', '제5조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-6', '작전지역 출입', '군 작전지역에 출입하는 취재진은 군 당국이 정하는 소정의 절차에 따라 서면으로 출입등록을 하고 안전조치에 협조해야 한다.', '군 취재·보도 기준', '제6조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-7', '정보제공방법', '군은 국민들에게 브리핑, 보도자료 등 올바른 정보를 알리기 위한 방법을 강구하고 가용 여건을 고려 작전 현장 부근에 보도본부를 설치해 취재 및 보도를 지원한다.', '군 취재·보도 기준', '제7조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-8', '군사기밀 보호', '언론은 작전상황과 관련된 장비 배치와 수량, 군부대의 특정한 위치를 드러내는 정보나 사진, 적 정보수집 방법 등에 대한 사항을 보도하는 것이 적을 이롭게 할 수 있다는 점을 유념해야 한다.', '군 취재·보도 기준', '제8조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-9', '통제구역 준수', '취재진이 작전 현장에 대한 취재를 할 경우 작전부대에서 제시하는 접근 통제선을 준수해야 한다.', '군 취재·보도 기준', '제9조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-10', '안전조치 협조', '군과 언론사는 현장 취재진의 안전대책 강구에 최대한 협조해야 한다.', '군 취재·보도 기준', '제10조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-11', '작전현장 갈등 조정', '군 작전 현장에서 군 관계관 및 취재보도진 사이에 갈등이나 마찰 상황이 발생할 경우에는 군과 언론이 국방부 대변인실과 해당 언론매체 담당데스크와의 협의를 통해 합리적 조정방안을 강구한다.', '군 취재·보도 기준', '제11조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-12', '인권 존중 보도', '군 작전 수행 중 전·사상자, 입원환자, 가족 및 장례 등에 관한 취재는 개인의 사생활과 인권을 존중하고 숭고한 희생이 폄훼되지 않도록 한다', '군 취재·보도 기준', '제12조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-13', '보호장비 대여 및 비용부담', '군은 취재진의 신변안전을 위한 보호장비를 대여하거나 대피장소 및 숙식, 이동수단을 제공할 수 있다. 현장 접근이 어려운 도서지역에서 비상사태가 발생했을 때는 군에서 기본적 이동수단 등을 제공할 수 있으나 숙식에 따른 경비와 추가적인 장비운용에 따른 비용은 해당 언론사에서 부담한다.', '군 취재·보도 기준', '제13조', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S1', '사실 기반 신속 정확 브리핑', '군은 비상상황 발생시 ''사실에 입각하여, 신속하고, 정확한'' 정보제공 및 브리핑을 한다.', '군 취재·보도 기준', '실천수칙 ①', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S2', '취재진 안전조치', '군은 현장취재가 승인된 취재보도진의 신변안전을 위해 최대한 안전조치를 마련한다.', '군 취재·보도 기준', '실천수칙 ②', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S3', '현장보도본부 설치·운영', '군은 비상상황 조치의 일환으로 필요시 현장보도본부를 설치하여 브리핑 및 취재활동을 지원한다.', '군 취재·보도 기준', '실천수칙 ③', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S4', '취재기본규칙(ground rules) 준수', '언론은 진행 중인 작전사항, 작전계획, 기밀사항은 사전에 동의한 절차와 현장 작전 부대가 요청하는 취재기본규칙(ground rules)을 준수한다.', '군 취재·보도 기준', '실천수칙 ④', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S5', '군 당국 기본 절차 준수', '언론은 현장취재나 브리핑이 있을 때 군 당국이 정한 기본적인 절차를 준수한다.', '군 취재·보도 기준', '실천수칙 ⑤', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S6', '공동취재단 구성', '언론은 작전 현장 여건에 따라 공동취재단 구성을 원칙으로 하며, 공동 취재단은 국방부 출입등록매체를 중심으로 한다.', '군 취재·보도 기준', '실천수칙 ⑥', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('MRG-S7', '전·사상자 인권 존중 보도', '언론은 작전 중 전사 또는 순직하거나 부상을 당한 장병의 인권을 존중하고, 그들의 희생이 폄훼되지 않도록 보도한다', '군 취재·보도 기준', '실천수칙 ⑦', 3, '도메인 특화 규범 (국가안보 위기시 군 취재·보도)', NULL, 'military_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-P', '자살예방 보도준칙 4.0 전문', '자살보도에는 사회적 책임이 따릅니다. <자살예방 보도준칙 4.0>은 언론인과 콘텐츠 생산자 등에게 자살보도의 사회적 책임을 인식시키고, 자살예방에 동참할 것을 권유하고자 마련한 기준입니다. 잘못된 자살보도는 모방 자살을 일으킬 수 있습니다. 반면에 자살보도 방식을 바람직하게 바꾸면 소중한 생명을 구할 수 있습니다. 인터넷·스마트 기기가 대중화된 디지털 시대에는 자살 관련 보도와 콘텐츠가 무분별하게 재생산될 수 있어 언론과 콘텐츠 생산자의 윤리적·실질적인 각성이 더욱 필요합니다. 기자·언론사·언론단체 등이 활동하는 매스미디어, 경찰청·소방청 등 국가기관, 블로그·사회관계망 서비스(SNS) 등 1인 미디어에서 함께 이 준칙을 실천할 때 비로소 자살을 예방하고 소중한 생명을 지킬 수 있습니다.', '자살예방 보도준칙 4.0', '전문', 3, '도메인 특화 규범 (자살예방 보도, 2024년 개정)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('SPG-1', '원칙 1: 자살 사건 보도 자제', '자살 사건은 가급적 보도하지 않는다.', '자살예방 보도준칙 4.0', '원칙 1', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-1-1', '보도 자제와 자살예방 효과', '자살 사건을 보도하지 않으면 자살예방에 도움이 됩니다. 자살 사건을 보도하지 않는 나라에서 자살이 감소하는 사례가 보고됐습니다. 사람의 생명보다 더 큰 보도의 가치는 없습니다. 자살이 부각된 보도는 또 다른 자살을 유발할 수 있으므로 방송 보도나 신문지면 등에서 자살 사건을 가급적 다루지 않습니다. 특히 유명인의 자살은 파급력이 크므로 보도에 더욱 신중해야 합니다. 1인 미디어에서 다룬 자살 사건을 재인용하는 보도는 하지 말아야 합니다.', '자살예방 보도준칙 4.0', '원칙 1-1', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-1-2', '보도 시 표현 기준: ''사망하다''·''숨지다'' 사용', '자살 사건을 보도해야 할 경우, 기사 제목에 ''사망하다'' 또는 ''숨지다''와 같은 표현을 사용합니다. ''극단적 선택''이라는 표현 등 자살을 ''선택'' 사항인 것처럼 오인할 수 있게 하는 용어를 쓰지 않습니다. 자살을 미화하는 표현도 사용하지 않습니다. 사회적 문제 제기를 위한 자살보도도 구체적인 내용을 언급하는 것을 피하고 건설적인 해결 방법을 제시합니다.', '자살예방 보도준칙 4.0', '원칙 1-2', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-1-3', '자살 합리화 금지', '자살을 합리화하지 않습니다. 자살로 불명예스러운 사건이 종결되거나 자살이 억울함을 해소하는 방법이 될 수 있다는 논리가 전달되지 않도록 유의합니다. ''벼랑 끝 선택'', ''어쩔 수 없는 선택'', ''마지막 탈출구'', ''○○을 이기지 못해 뒤따라 자살'' 등과 같은 표현을 사용하지 않습니다.', '자살예방 보도준칙 4.0', '원칙 1-3', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-1-4', '객관적·신중한 보도', '자살을 객관적이고 신중하게 다룹니다. 자살의 명확한 사실관계가 확인되기 전까지 자살을 단정하는 보도는 삼가야 하며, 명확한 사실관계가 확인된 후 보도하는 것이 좋습니다. 목격자의 인터뷰 내용이나 관련 기관의 발표라도 추측성 보도를 하지 않습니다. 다른 사람을 살해하고 자살하는 행위를 ''동반자살''로 표현하지 않습니다. 이는 ''살해 후 자살''이나 ''자살교사''로 표현해야 하는 범죄 행위입니다.', '자살예방 보도준칙 4.0', '원칙 1-4', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-2', '원칙 2: 자살 방법·도구·장소·동기 비보도', '구체적인 자살 방법, 도구, 장소, 동기 등을 보도하지 않는다.', '자살예방 보도준칙 4.0', '원칙 2', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-2-1', '자살 방법·도구·장소 비보도', '자살 방법, 도구, 장소는 구체적으로 보도하지 않습니다. 자살 방법 등을 상세하게 설명·묘사하는 행위는 자살을 생각하고 있는 사람들에게 자살에 관한 정보를 제공하는 것과 같습니다.', '자살예방 보도준칙 4.0', '원칙 2-1', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-2-2', '자살 동기 단순화·추정 금지', '자살 동기를 단순화하거나 추정하지 않습니다. 자살은 복잡한 요인들로 일어나므로 표면적인 자살 동기만을 보도할 경우 잘못된 보도가 될 수 있습니다. 또한 유사한 상황에 처한 사람에게 모방 자살을 일으킬 수 있습니다.', '자살예방 보도준칙 4.0', '원칙 2-2', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-2-3', '시각 자료 사용 자제', '자살 사건과 관련한 시각 자료 사용을 자제합니다. 자살 장소, 방법, 도구 등에 관련한 사진이나 영상 또는 자살을 암시하는 자료 등은 사용하지 않습니다. 유명인 자살은 파급력이 더욱 크므로 고인의 자살과 관련한 영상이나 사진 사용을 자제해야 합니다.', '자살예방 보도준칙 4.0', '원칙 2-3', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-3', '원칙 3: 고인의 인격·유족의 사생활 존중', '고인의 인격과 유족의 사생활을 존중한다.', '자살예방 보도준칙 4.0', '원칙 3', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-3-1', '고인·유족 신분 비노출', '고인과 유족의 신분을 노출하지 않습니다. 고인의 거주지, 나이, 직업, 경력 등 구체적인 신상을 밝히는 것은 유족(특히 어린 자녀)에게 2차 피해를 유발할 수 있습니다.', '자살예방 보도준칙 4.0', '원칙 3-1', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-3-2', '유서 관련 사항 비보도', '유서와 관련한 사항을 보도하지 않습니다. 고인과 유족의 사생활을 보호하고 자살에 대한 합리화를 방지하기 위해 유서와 관련한 사항은 보도하지 않습니다.', '자살예방 보도준칙 4.0', '원칙 3-2', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-3-3', '유족 심리 상태 배려', '유족의 심리 상태를 배려합니다. 고인의 갑작스러운 사망 소식으로 충격을 받고 절망감을 느낄 유족이 자살 사건 보도로 더욱 고통받을 수 있다는 점을 감안해야 합니다.', '자살예방 보도준칙 4.0', '원칙 3-3', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-3-4', '고인의 인격·비밀 보호', '고인의 인격과 비밀은 살아있는 사람처럼 보호해야 합니다. 고인의 인격을 침해하거나 비밀을 노출하는 보도는 고인과 유족의 권리나 법익을 해칠 수 있습니다.', '자살예방 보도준칙 4.0', '원칙 3-4', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-4', '원칙 4: 자살예방 정보 제공', '자살예방을 위한 정보를 제공한다.', '자살예방 보도준칙 4.0', '원칙 4', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-4-1', '잘못된 믿음 교정 정보 제공', '자살에 대한 잘못된 믿음을 바로잡을 수 있는 정보를 제공합니다.', '자살예방 보도준칙 4.0', '원칙 4-1', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-4-2', '긴급 도움 기관 정보 제공', '자살예방 관련 긴급 도움 요청 기관 정보를 제공합니다. 우울감 등 말하기 어려운 고민이 있거나, 주변에 이런 어려움을 겪는 가족·지인이 있을 경우 자살예방 상담전화 ☎109 또는 SNS상담 마들랜(마음을 들어주는 랜선친구)에서 24시간 전문가의 상담을 받을 수 있습니다.', '자살예방 보도준칙 4.0', '원칙 4-2', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-4-3', '전문가 의견 반영·생명 소중함 강조', '전문가의 의견을 반영하고 생명의 소중함을 강조합니다.', '자살예방 보도준칙 4.0', '원칙 4-3', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('SPG-4-4', '자살의 부정적 결과 전달', '자살의 부정적 결과를 명확히 전달합니다.', '자살예방 보도준칙 4.0', '원칙 4-4', 3, '도메인 특화 규범 (자살예방 보도)', NULL, 'suicide_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-P', '재난보도준칙 전문', '재난이 발생했을 때 정확하고 신속하게 재난 정보를 제공해 국민의 생명과 재산을 지키는 것도 언론의 기본 사명 중 하나이다. 언론의 재난보도에는 방재와 복구 기능도 있음을 유념해 피해의 확산을 방지하고 피해자와 피해지역이 어려움을 극복하고 하루빨리 일상으로 돌아갈 수 있도록 기능해야 한다. 재난 보도는 사회적 혼란이나 불안을 야기하지 않도록 노력해야 하며, 재난 수습에 지장을 주거나 피해자의 명예나 사생활 등 개인의 인권을 침해하는 일이 없도록 각별히 유의해야 한다.', '재난보도준칙', '전문', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('DRG-1', '목적', '이 준칙은 재난이 발생했을 때 언론의 취재와 보도에 관한 세부 기준을 제시함으로써 취재 현장의 혼란을 방지하고 언론의 원활한 공적 기능 수행에 기여함을 목적으로 한다.', '재난보도준칙', '제1조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-2', '적용 범위', '이 준칙은 태풍·홍수 등 자연 재난, 화재·붕괴·폭발 등 인적 재난, 국가기반체계 마비, 급성 감염병 등 질병재난, 기타 대형 사건 사고 등 사회적 재난에 적용한다.', '재난보도준칙', '제2조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-3', '정확한 보도', '언론은 재난 발생 사실과 피해 및 구조상황 등 재난 관련 정보를 국민에게 최대한 정확하고 신속하게 보도해야 한다.', '재난보도준칙', '제3조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-4', '인명구조와 수습 우선', '재난현장 취재는 긴급한 인명구조와 보호, 사후수습 등의 활동에 지장을 주지 않는 범위 안에서 이루어져야 한다. 재난관리 당국이 설정한 폴리스라인, 포토라인 등 취재제한은 특별한 사유가 없는 한 준수한다.', '재난보도준칙', '제4조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-5', '피해의 최소화', '언론의 역할 중에는 방재와 복구기능도 있음을 유념해 재난 피해를 최소화하는 데 기여해야 한다.', '재난보도준칙', '제5조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-6', '예방 정보 제공', '언론은 사실 전달뿐만 아니라 새로 발생할지도 모르는 피해를 예방하기 위해 안내와 사전 정보를 제공하고, 피해자 및 지역주민에게 필요한 생활정보나 행동요령 등을 전달하는 데도 노력해야 한다.', '재난보도준칙', '제6조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-7', '비윤리적 취재 금지', '취재를 할 때는 신분을 밝혀야 한다. 신분 사칭이나 비밀 촬영 및 녹음 등 비윤리적인 수단과 방법을 통한 취재는 하지 않는다.', '재난보도준칙', '제7조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-8', '통제지역 취재', '병원, 피난처, 수사기관 등 출입을 통제하는 곳에서의 취재는 특별한 사유가 없는 한 관계기관의 동의를 얻어야 한다.', '재난보도준칙', '제8조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-9', '현장 데스크 운영', '언론사는 충실한 재난 보도를 위해 가급적 현장 데스크를 두며, 본사 데스크는 현장 상황이 왜곡돼 보도되지 않도록 현장 데스크와 취재기자의 의견을 최대한 존중한다.', '재난보도준칙', '제9조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-10', '무리한 보도 경쟁 자제', '언론사와 제작책임자는 속보 경쟁에 치우쳐 현장기자에게 무리한 취재나 제작을 요구함으로써 정확성을 소홀히 하도록 해서는 안 된다.', '재난보도준칙', '제10조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-11', '공적 정보의 취급', '피해 규모나 피해자 명단, 사고 원인과 수사 상황 등 중요한 정보에 관한 보도는 책임 있는 재난관리당국이나 관련기관의 공식 발표에 따르되 공식발표의 진위와 정확성에 대해서도 최대한 검증해야 한다.', '재난보도준칙', '제11조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-12', '취재원에 대한 검증', '재난과 관련해 인터뷰나 코멘트를 하는 인물에 대해서는 사전에 신뢰성과 전문성을 충분히 검증해야 한다. 평소 검증된 재난 전문가들의 명단을 확보해 놓고 수시로 검증하여 활용하도록 한다.', '재난보도준칙', '제12조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-13', '유언비어 방지', '모든 정보는 출처를 공개하고 실명으로 보도하는 것을 원칙으로 한다. 확인되지 않거나 불확실한 정보는 보도를 자제함으로써 유언비어의 발생이나 확산을 막아야 한다.', '재난보도준칙', '제13조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-14', '단편적인 정보의 보도', '사건 사고의 전체상이 파악되지 않은 상황에서 불가피하게 단편적인 정보를 보도할 때는 부족하거나 더 확인돼야 할 사실이 무엇인지를 함께 언급함으로써 독자나 시청자가 정보의 한계를 인식할 수 있도록 노력한다.', '재난보도준칙', '제14조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-15', '선정적 보도 지양', '피해자 가족의 오열 등 과도한 감정 표현, 부적절한 신체 노출, 재난 상황의 본질과 관련이 없는 흥미위주의 보도 등은 하지 않는다. 자극적인 장면의 단순 반복 보도는 지양한다.', '재난보도준칙', '제15조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-16', '감정적 표현 자제', '개인적인 감정이 들어간 즉흥적인 보도나 논평은 하지 않으며 냉정하고 침착한 보도 태도를 유지한다. 자극적이거나 선정적인 용어, 공포심이나 불쾌감을 줄 수 있는 용어는 사용하지 않는다.', '재난보도준칙', '제16조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-17', '정정과 반론 보도', '보도한 내용이 사실과 다를 경우에는 독자나 시청자가 납득할 수 있는 적절한 방법으로 신속하고 분명하게 바로잡아야 한다. 반론 보도 요구가 타당하다고 판단될 때는 전향적으로 수용해야 한다.', '재난보도준칙', '제17조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-18', '피해자 보호', '취재 보도 과정에서 사망자와 부상자 등 피해자와 그 가족, 주변사람들의 의견이나 희망사항을 존중하고, 그들의 명예나 사생활, 심리적 안정 등을 침해해서는 안 된다.', '재난보도준칙', '제18조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-19', '신상공개 주의', '피해자와 그 가족, 주변사람들의 상세한 신상 공개는 인격권이나 초상권, 사생활 침해 등의 우려가 있으므로 최대한 신중해야 한다.', '재난보도준칙', '제19조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-20', '피해자 인터뷰', '피해자와 그 가족, 주변사람들에게 인터뷰를 강요해서는 안 된다. 인터뷰를 원치 않을 경우에는 그 의사를 존중해야 하며 비밀 촬영이나 녹음 등은 하지 않는다. 인터뷰에 응한다 할지라도 질문 내용과 질문 방법, 인터뷰 시간 등을 세심하게 배려해야 한다.', '재난보도준칙', '제20조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-21', '미성년자 취재', '13세 이하의 미성년자는 원칙적으로 취재를 하지 않는다. 꼭 필요하다고 판단될 경우에는 부모나 보호자의 동의를 얻어야 한다.', '재난보도준칙', '제21조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-22', '피해자 대표와의 접촉', '피해자와 그 가족들이 대표자를 정했을 경우에는 이들의 의견을 적절히 수용하고 보도에 반영함으로써 피해자와 언론 사이에 불필요한 마찰이나 갈등, 오해가 생기지 않도록 노력한다.', '재난보도준칙', '제22조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-23', '과거 자료 사용 자제', '과거에 발생했던 유사한 사건 사고의 기사 사진 영상 음성 등을 사용하는 것은 해당 사건 사고와 관련된 사람의 아픈 기억을 되살리고 불필요한 불안감을 부추길 수 있으므로 가급적 자제한다. 부득이 사용할 경우에는 과거 자료라는 점을 분명히 밝힌다.', '재난보도준칙', '제23조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-24', '안전 조치 강구', '언론사와 취재진은 취재 현장이 취재진의 생명과 안전을 위협할 수 있다고 판단될 경우에는 취재에 앞서 적절한 안전 조치를 강구해야 한다.', '재난보도준칙', '제24조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-25', '안전 장비 준비', '언론사는 재난 취재에 대비해 언제든지 취재진에게 지급할 수 있도록 기본적인 안전 보호 장비를 준비해두어야 한다. 취재진은 반드시 안전 장비를 갖추고 취재에 임해야 한다.', '재난보도준칙', '제25조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-26', '재난 법규의 숙지', '재난 현장에 투입되는 취재진은 사내외에서 사전 교육을 받거나 회사가 제정한 준칙 등을 통해 재난 관련 법규를 숙지해야 하며 반드시 안전지침을 준수해야 한다.', '재난보도준칙', '제26조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-27', '충분한 취재지원', '언론사는 재난 현장 취재진의 안전 교통 숙박 식사 휴식 교대 보상 등을 충분히 지원해야 하며, 사후 심리치료나 건강검진 등의 기회를 제공해야 한다.', '재난보도준칙', '제27조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-28', '취재협의체 구성', '각 언론사는 이 준칙이 제대로 지켜질 수 있도록 협의하고 협력하기 위해 필요한 경우 현장 데스크 등 각사의 대표가 참여하는 ''재난현장 취재협의체''를 구성할 수 있다.', '재난보도준칙', '제28조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-29', '취재협의체 권한', '취재협의체는 이 준칙에 따라 원활한 취재와 보도를 할 수 있도록 재난관리 당국에 현장 브리핑룸 설치, 브리핑 주기 결정, 필요한 정보의 공개 등과 관련해 협조를 요구할 수 있다.', '재난보도준칙', '제29조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-30', '취재협의체 의견 개진', '취재협의체는 재난관리 당국이 폴리스라인이나 포토라인 설정 등 취재에 직간접적인 영향을 주는 사안을 결정할 경우 사전에 의견을 개진하고 사후 운영 방법에 대해서도 개선이나 협의를 요청할 수 있다.', '재난보도준칙', '제30조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-31', '대표 취재', '취재협의체는 재난 현장에 대한 접근이 제한받을 경우, 과도한 취재인원으로 피해자의 인권을 침해하거나 구조작업 등에 지장을 줄 우려가 있을 경우, 기타 필요하다고 판단될 경우에는 논의를 거쳐 대표 취재를 할 수 있다.', '재난보도준칙', '제31조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-32', '초기 취재 지원', '취재협의체는 취재 초기에 취재진이 미처 준비하지 못한 생활용품이나 단기간의 숙박 장소, 전기·통신·이동수단 등을 확보하기 위해 현장의 관계당국이나 자원봉사단체 등과 협의할 수 있다.', '재난보도준칙', '제32조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-33', '현장 제재', '이 준칙에 따라 취재협의체가 합의한 사항을 위반한 언론사의 취재진에 대해서는 취재협의체 차원에서 공동취재 배제 등의 불이익을 줄 수 있다.', '재난보도준칙', '제33조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-34', '지원 준비와 교육', '언론사는 재난보도에 관한 교재를 만들어 비치하고 사전 교육을 실시함으로써 취재진의 빠른 현장 적응을 돕는다.', '재난보도준칙', '제34조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-35', '교육 참여 독려', '언론사는 사내외에서 실시하는 각종 재난교육과 훈련 프로그램에 소속 기자들이 적극적으로 참여하도록 독려한다. 언론사는 가능하면 재난보도 담당 기자를 사전에 지정해 평소 전문지식을 기르도록 지원한다.', '재난보도준칙', '제35조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-36', '사후 모니터링', '언론사는 재난 취재에서 돌아온 취재진을 대상으로 설문조사나 의견청취, 보고서 제출 등을 통해 다음 재난 취재시 더 실질적이고 효율적인 지원을 할 수 있는 방안을 강구한다.', '재난보도준칙', '제36조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-37', '재난취약계층에 대한 배려', '언론사는 노약자, 지체부자유자, 다문화가정, 외국인 등 재난 취약계층에게도 재난정보를 신속하고 정확하게 전달할 수 있는 방안을 마련하는데 힘쓴다.', '재난보도준칙', '제37조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-38', '언론사별 준칙 제정', '언론사는 필요할 경우 이 준칙을 토대로 각사의 사정에 맞춰 구체적이고 효율적인 자체 준칙을 만들어 시행한다.', '재난보도준칙', '제38조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-39', '재난관리당국과의 협조체제', '언론사는 회사별로, 또는 소속 언론사 단체를 통해 재난관리당국 및 유관기관과의 상시적인 협조체제를 구축함으로써 효율적인 방재와 사후수습, 신속 정확한 보도를 위해 노력한다.', '재난보도준칙', '제39조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('DRG-40', '준칙 준수 의사의 공표', '이 준칙의 제정에 참여했거나 준칙에 동의하는 언론사는 자체 매체를 통해 적절한 방법으로 준칙 준수 의사를 밝힌다.', '재난보도준칙', '제40조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('DRG-41', '자율 심의', '이 준칙의 제정에 참여했거나 준칙에 동의하는 언론사는 각 언론사별, 또는 소속 언론사 단체별로 자율심의기구를 만들어 준칙 준수 여부를 심의하도록 한다.', '재난보도준칙', '제41조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('DRG-42', '사후 조치', '이 준칙의 제정에 참여했거나 준칙에 동의하는 언론사의 특정 기사나 보도가 준칙을 어겼다고 판단될 경우에는 심의기구별로 적절한 제재조치를 취한다.', '재난보도준칙', '제42조', 3, '도메인 특화 규범 (재난 보도)', NULL, 'disaster_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('IRG-P', '감염병보도준칙 전문', '감염병이 발생했을 때 정확하고 신속한 정보는 국민의 생명 보호와 안전에 직결되는 만큼 무엇보다 정확한 사실에 근거해 보도해야 한다. 추측성 기사나 과장된 기사는 국민들에게 혼란을 야기한다는 점을 명심하고, 감염병을 퇴치하고 피해 확산을 막는데 우리 언론인도 다함께 노력한다. 감염병 관련 기사를 작성할 때는 반드시 전문가의 자문을 구한 뒤 작성하도록 하고, 과도한 보도 경쟁으로 피해자들의 사생활이 침해되지 않도록 최대한 노력한다.', '감염병보도준칙', '전문', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('IRG-1', '감염병 보도의 기본 내용', '감염병 보도는 해당 병에 취약한 집단을 알려주고, 예방법 및 행동수칙을 우선적, 반복적으로 제공한다. 감염병 치료에 필요한 의료기관 등에 대한 정보를 제공한다. 감염병 관련 의학적 용어는 일반인들이 이해하기 쉽게 전달한다.', '감염병보도준칙', '기본원칙 1', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-2', '신종 감염병의 보도', '발생 원인이나 감염 경로 등이 불확실한 신종 감염병의 보도는 현재 의학적으로 밝혀진 것과 밝혀지지 않은 것을 명확하게 구분하여 전달한다. 현재의 불확실한 상황에 대해 의과학 분야 전문가의 의견을 제시하며, 추측, 과장 보도를 하지 않는다. 감염병 발생 최초 보도 시 질병관리본부를 포함한 보건당국에 사실여부를 확인하고 보도하며, 정보원 명기를 원칙으로 한다.', '감염병보도준칙', '기본원칙 2', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-3', '감염 가능성에 대한 보도', '감염 가능성은 전문가의 의견이나 연구결과 등 과학적 근거를 바탕으로 보도한다. 감염병의 발생률, 증가율, 치명률 등 백분율 보도 시 실제 수치를 함께 전달한다. 감염의 규모를 보도할 때는 지역, 기간, 단위 등을 정확히 전달하고 환자수, 의심환자수 등을 구분해 보도한다.', '감염병보도준칙', '기본원칙 3', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-4', '감염병 연구 결과 보도', '감염병의 새로운 연구결과 보도 시 학술지 발행기관이나 발표한 연구자의 관점이 연구기관, 의료계, 제약 회사의 특정 이익과 관련이 있는지, 정부의 입장을 일방적으로 지지하는지 확인한다. 감염병 관련 연구결과가 전체 연구중의 중간 단계인지, 최종 연구결과물인지 여부를 확인한 후 보도한다.', '감염병보도준칙', '기본원칙 4', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-5', '감염인에 대한 취재·보도', '불확실한 감염병의 경우, 기자를 매개로 한 전파의 우려가 있기 때문에 감염인을 직접 대면 취재하지 않는다. 감염인은 취재만으로도 차별 및 낙인이 발생할 수 있으므로 감염인과 가족의 개인정보를 보호하고 사생활을 존중한다. 감염인에 대한 사진이나 영상을 취재·보도에 활용할 경우 본인 동의없이 사용하지 않는다.', '감염병보도준칙', '기본원칙 5', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-6', '의료기관 내 감염 보도', '의료기관 내 감염 확산에 대한 취재·보도 시, 치료환경에 대한 불안감 및 혼란을 고려해 원인과 현장 상황에 대해 감염전문가의 자문과 확인이 필요하다.', '감염병보도준칙', '기본원칙 6', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-7', '보도 시 주의해야 할 표현', '기사 제목에 패닉, 대혼란, 대란, 공포, 창궐 등 과장된 표현 사용을 삼간다. 기사 본문에 자극적인 수식어의 사용을 삼간다. 오인이 우려되는 다른 감염병과의 비교를 삼간다.', '감염병보도준칙', '기본원칙 7', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-R1', '권고: 특별취재팀 구성', '감염병 발생시, 각 언론사는 특별취재팀을 구성해 감염병에 대한 충분한 사전 교육을 받지 않은 기자들이 무분별하게 현장에 접근하는 일이 없도록 해야 한다.', '감염병보도준칙', '권고사항 1', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('IRG-R2', '권고: 보건당국 특별대책반 구성', '감염병 발생시, 보건당국은 언론인을 포함한 특별대책반(T/F)를 구성해, 관련 정보가 국민들에게 신속하고 정확하게 전달되도록 해야 하고, 위험 지역 접근취재 시 공동취재단을 구성해 기자들의 안전 및 방역에 대비해야 한다.', '감염병보도준칙', '권고사항 2', 3, '도메인 특화 규범 (감염병 보도)', NULL, 'infectious_disease_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-P', '선거여론조사보도준칙 전문', '선거는 민주주의를 구현하는 핵심적인 정치과정으로 공정하고 깨끗한 선거는 민주주의의 유지 및 발전을 위한 기본 전제이다. 유권자 등 미디어 이용자에게 후보자와 정당에 관한 정확하고 신뢰할만한 정보를 제공하는 것은 언론의 기본 사명 중 하나이다. 과학적 방법론에 기초하여 대표성을 확보한 전문적인 여론조사는 선거 기간 중 유권자에게 유용한 정보를 제공할 수 있다.', '선거여론조사보도준칙', '전문', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('EPG-1', '목적', '이 준칙은 선거여론조사의 활용과 보도에 관한 세부 기준을 제시함으로써 선거여론조사보도의 정확성, 객관성, 신뢰성을 제고하고 언론의 원활한 공적 기능 수행에 기여함을 목적으로 한다.', '선거여론조사보도준칙', '제1조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-2', '적용범위', '이 준칙은 공직선거법 제2조에 따른 공직선거, 교육감선거 등에 적용하며, 신문, 인터넷신문, 방송, 뉴스통신 등 미디어에 적용한다.', '선거여론조사보도준칙', '제2조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-3', '여론조사의 한계', '여론조사 수치가 곧 여론 그 자체는 아니므로 미디어는 여론조사 결과를 여론과 동일시해서는 안 되며, 수치에 과도한 의미를 부여해서는 안 된다.', '선거여론조사보도준칙', '제3조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-4', '과학성', '미디어는 대표성과 신뢰성이 의심되는 여론조사를 기획하거나 의뢰하지 않는다. 여론조사 결과를 보도할 때 정확성, 객관성, 신뢰성을 충족한 과학적 해석을 최고의 가치로 삼아야 하며, 여론조사 결과를 속보 경쟁의 대상으로 보지 말아야 한다. 여론조사 결과를 자의적으로 해석하거나 일상생활에서 다루는 숫자처럼 취급하지 말아야 한다.', '선거여론조사보도준칙', '제4조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-5', '공정성', '왜곡된 선거여론조사 결과가 보도되어 선거 운동에 오용되지 않도록 주의해야 한다. 미디어의 정치적 의도성이 의심되는 보도를 해서는 안 된다. 여론조사 결과 중 특정 정당, 후보자에게 유리한 내용만을 뽑아 단편적, 단락적 보도를 하지 않는다.', '선거여론조사보도준칙', '제5조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-6', '조사기관의 선정', '미디어는 과학성, 공정성 등의 여론조사 원칙을 준수하고 있는 전문 조사기관에 선거 여론조사를 의뢰해야 한다.', '선거여론조사보도준칙', '제6조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-7', '표본의 대표성 확보', '미디어가 선거여론조사를 실시하는 경우에는 당해 조사대상의 전 계층을 대표할 수 있도록 피조사자를 선정해야 한다. 대표성 있는 표집이 아닐 경우에는 표본이 왜곡될 가능성이 있다는 점을 늘 염두에 두어야 한다.', '선거여론조사보도준칙', '제7조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-8', '금지되는 조사행위', '특정 정당 또는 후보자에게 편향되도록 하는 어휘나 문장을 사용하여 질문하는 행위, 피조사자에게 응답을 강요하거나 유도하는 행위, 오락·사행성을 조장하는 조사, 피조사자 성명 공개 행위 등은 금지된다. 또한 특정 정당·후보자가 의뢰하거나 비용을 제공하는 여론조사, 비과학적 인터넷·ARS 여론조사도 기획·의뢰하지 않는다.', '선거여론조사보도준칙', '제8조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-9', '무리한 속보 경쟁 자제', '미디어는 특정 사건 발생 후 단기간에 과학성, 공정성이 결여된 여론조사를 실시해 무리한 보도를 해서는 안 된다.', '선거여론조사보도준칙', '제9조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-10', '품질의 제고', '미디어는 비용과 시간이 들더라도 고품질 여론조사를 실시하도록 노력한다. 저품질 불량 여론조사를 여러 번 하기보다는 횟수를 줄여 과학성, 공정성을 갖춘 여론조사를 하는 것이 바람직하다.', '선거여론조사보도준칙', '제10조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-11', '여론조사의 감리', '미디어는 전문 조사기관이 조사 설계를 제대로 했는지, 표본은 확률에 입각해 제대로 추출하는지, 실제조사는 성실히 수행하는지 등을 감리하기 위해 조사 전후에 전문가의 조언을 얻어 감리하는 것이 바람직하다.', '선거여론조사보도준칙', '제11조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-12', '대상 여론조사', '미디어는 선거여론조사 결과를 공표·보도할 때에는 중앙심의위원회 홈페이지에 등록된 선거여론조사 결과만을 공표·보도해야 한다.', '선거여론조사보도준칙', '제12조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-13', '공표·보도해야 할 사항', '정당과 후보자의 지지율 및 선호도와 관련한 여론조사 보도는 중앙심의위원회 선거여론조사기준을 참조하여 보도한다.', '선거여론조사보도준칙', '제13조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-14', '인용의 제한', '특정 정당 또는 후보자가 의뢰한 경우, 질문이 편향된 경우, 과학적 표집과정을 거치지 않은 경우 등은 인용하지 않아야 한다.', '선거여론조사보도준칙', '제14조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-15', '인용시 표기 사항', '이미 보도된 타 기관의 결과를 인용하여 보도할 때에는 해당 선거여론조사의 조사의뢰자, 조사기관, 조사기간 등과 함께 중앙심의위원회 홈페이지 참조를 밝혀야 한다.', '선거여론조사보도준칙', '제15조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-16', '오차범위 내 결과의 보도', '지지율 또는 선호도가 오차범위 안에 있을 경우 순위를 매기거나 서열화하지 않고 ''경합'' 또는 ''오차범위 내에 있다''고 보도한다. ''오차범위 내에서 앞섰다'' 등의 표현은 사용하지 않는다.', '선거여론조사보도준칙', '제16조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-17', '조사 결과의 비교', '서로 다른 시점에서 실시된 여론조사는 그 조사방법이 동일한 경우에만 상호비교가 가능하다. ''지지율 조사''와 ''선호도 조사''처럼 성격이 다른 여론조사들을 직접 비교하지 않는다.', '선거여론조사보도준칙', '제17조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-18', '항목 무응답의 고려', '찬성과 반대의 의견을 묻는 조사의 경우 ''무응답자'' 및 ''모르겠다''라고 응답한 사람의 비율에 특히 주의해야 한다.', '선거여론조사보도준칙', '제18조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-19', '주관적 표현 자제', '조사결과에 대해 ''의외의'', ''예상을 넘는'', ''기대에 못 미치는'' 등 주관적일 수 있는 표현은 가급적 자제한다. 여론조사 결과를 자의적으로 해석하여 주관적인 견해나 판단을 보도하는 것을 자제해야 한다.', '선거여론조사보도준칙', '제19조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-20', '인포그래픽 제작 주의', '후보자나 정당 간 지지율 또는 선호도의 차이가 오차한계 내에 있을 경우 그래프, 그림, 표 등은 동등한 크기와 조건으로 제작해야 한다. 다른 조사와 비교할 경우 그래프 등을 사용해 그 차이를 과장 또는 축소하지 않아야 한다.', '선거여론조사보도준칙', '제20조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-21', '전문 용어에 대한 해설', '미디어는 여론조사 보도 시 신뢰수준, 표본오차, 오차범위, 응답률, 가중값 등 전문용어를 매체 이용자들이 쉽게 이해할 수 있도록 보도해야 한다.', '선거여론조사보도준칙', '제21조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-22', '순위 일변도 보도 지양', '미디어는 선거 기간 중 정당이나 후보자의 지지율과 선호도에만 집중할 것이 아니라 정책 및 공약에 충분한 관심을 기울여 보도해야 한다.', '선거여론조사보도준칙', '제22조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-23', '하위표본 분석 주의', '여론조사 결과를 성별, 연령별, 지역별 등 하위표본으로 나누어 추가 분석한 결과를 보도할 때 통계적으로 의미 없는 차이를 부각시키지 말아야 한다.', '선거여론조사보도준칙', '제23조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-24', '지원 준비와 교육', '언론사는 선거여론조사에 관한 교재를 비치하고 선거보도 종사자에게 사전 교육을 실시함으로써 정확하고 신뢰할 수 있는 보도를 할 수 있도록 한다.', '선거여론조사보도준칙', '제24조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-25', '교육 참여 독려', '언론사는 사내외에서 실시하는 각종 선거보도교육 프로그램에 소속 기자들이 적극적으로 참여하도록 독려한다.', '선거여론조사보도준칙', '제25조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-26', '언론사별 준칙 제정', '언론사는 필요할 경우 이 준칙을 토대로 각 사의 사정에 맞춰 구체적이고 효율적인 자체 준칙을 만들어 시행한다.', '선거여론조사보도준칙', '제26조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('EPG-27', '준칙 준수 의사의 공표', '이 준칙의 제정에 참여했거나 준칙에 동의하는 언론사는 자체 매체를 통해 적절한 방법으로 준칙 준수 의사를 밝힌다.', '선거여론조사보도준칙', '제27조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('EPG-28', '심의', '이 준칙의 제정에 참여했거나 준칙에 동의하는 언론사의 특정 기사나 보도가 준칙을 어겼다고 판단될 경우에는 심의기구별로 적절한 제재조치를 취한다.', '선거여론조사보도준칙', '제28조', 3, '도메인 특화 규범 (선거·여론조사 보도)', NULL, 'election_poll_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('PRG-P', '평화통일과 남북 화해 협력을 위한 보도 제작 준칙 전문', '분단된 조국의 통일은 온 겨레의 염원이다. 그러나 지금까지 우리 언론은 남북관계 및 통일문제 보도·제작에서 화해와 신뢰 분위기 조성에 기여하기보다는 불신과 대결의식을 조장함으로써 반통일적 언론이라는 오명을 씻어내지 못했다. 이같은 반성 위에서 언론 3단체는 우리 언론이 통일언론으로 거듭나기 위한 다짐으로 공동의 보도·제작 규범을 제시한다.', '평화통일 보도 준칙', '전문', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('PRG-T1', '총강 1: 상호존중과 호칭', '우리는 대한민국과 조선민주주의인민공화국으로 나누어진 남과 북의 현실을 인정하며, 상호존중과 평화통일을 준비하는 차원에서 상대방의 국명과 호칭을 있는 그대로 사용함을 원칙으로 한다.', '평화통일 보도 준칙', '총강 1', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('PRG-T2', '총강 2: 객관적 보도·냉전 편견 탈피', '우리는 냉전시대에 형성된 선입견과 편견에서 벗어나 객관적으로 보도·제작함으로써 남북 사이의 공감대를 넓혀 나간다.', '평화통일 보도 준칙', '총강 2', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('PRG-T3', '총강 3: 법적·제도적 장애 타파', '우리는 남북관계 보도·제작에서 언론의 자유를 근본적으로 가로막는 법적·제도적 장애를 타파한다.', '평화통일 보도 준칙', '총강 3', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-T4', '총강 4: 민족문화 공유·공동번영', '우리는 남과 북의 우수한 민족문화 유산을 공유하고 민족의 공동번영을 추구할 수 있는 기사 및 프로그램 개발에 힘쓴다.', '평화통일 보도 준칙', '총강 4', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-T5', '총강 5: 다양한 의견 공정 반영', '우리는 통일문제에 관한 사회 각계의 다양한 의견을 공정하게 반영하여 민주적인 여론형성에 기여한다.', '평화통일 보도 준칙', '총강 5', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R1', '보도실천 1: 남북 긴장해소 노력', '남북간의 평화를 저해할 수 있는 군비증강 등 제반문제에 관심을 기울이며, 남북간 긴장 및 불의의 사고 발생시 신속하고 평화적인 해결을 이끌어 내는 데 초점을 맞춰 보도한다.', '평화통일 보도 준칙', '보도실천 1', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R2', '보도실천 2: 인물 호칭·직책 존중', '조선민주주의인민공화국의 인물에 대한 호칭은 대한민국의 그것과 마찬가지로 성명 다음에 직책을 붙여 호칭한다.', '평화통일 보도 준칙', '보도실천 2', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R3', '보도실천 3: 관급자료 보도 유의', '조선민주주의인민공화국에 대한 관급 보도자료의 무절제한 인용·전재를 피하고 최대한 확인절차를 거쳐서 보도한다.', '평화통일 보도 준칙', '보도실천 3', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R4', '보도실천 4: 남북 언론인 간 합의사항 유의', '기사 작성·보도 시 남북 언론인 간 합의사항에 유의한다.', '평화통일 보도 준칙', '보도실천 4', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R5', '보도실천 5: 외신보도 신중 인용', '외신을 활용한 특정세력의 목적성 여론조성을 경계하며, 제3국이 자국의 이익을 관철하기 위해 의도적으로 유포하는 외신보도는 인용하지 않는다.', '평화통일 보도 준칙', '보도실천 5', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R6', '보도실천 6: 1차자료 적극 활용', '조선민주주의인민공화국의 신문·방송·통신 보도와 잡지 등 1차자료에서 보도가치가 있다고 판단되는 것은 적극 활용한다.', '평화통일 보도 준칙', '보도실천 6', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R7', '보도실천 7: 각종 추측보도 지양', '국내외 관계자들이 무책임하게 유포하는 각종 설은 보도하지 않는다. 다만 취재원을 확인할 수 있는 경우는 예외로 한다.', '평화통일 보도 준칙', '보도실천 7', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R8', '보도실천 8: 사진·화면 사용 절제', '해당기사와 무관한 자극적인 화면이나 사진을 사용하지 않으며, 냉전과 대결의 시각보다 남북간 화해와 협력을 이끌어 내는 데 노력한다.', '평화통일 보도 준칙', '보도실천 8', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R9', '보도실천 9: 희화적인 소재 지양', '남북간 언어, 문화, 생활의 차이와 상호 이질감을 우리의 잣대로 평가하거나 보도에 희화적 소재로 삼지 않는다.', '평화통일 보도 준칙', '보도실천 9', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-R10', '보도실천 10: 망명자의 증언 취사', '망명자의 증언은 그로부터 신뢰성을 확보할 수 있는 부분에 대해서만 기사화하도록 한다. 전언이나 추정 등을 기사화해야 할 경우는 ''전언'', ''추정'' 등을 명기한다.', '평화통일 보도 준칙', '보도실천 10', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M1', '제작실천 1: 정보제공 적극 편성', '조선민주주의인민공화국 관련 프로그램 편성시 형식적·소극적 편성에서 벗어나 다큐멘터리·드라마·오락물 등 각 장르별로 적극 편성하며, 남북 관련 긴급 혹은 특집프로그램 편성시 정치적 의도가 없는지 특히 유의한다.', '평화통일 보도 준칙', '제작실천 1', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M2', '제작실천 2: 통일지향 가치 추구', '기획, 출연자 선정, 편집 등의 제작과정에서 민족동질성 회복, 화해·공존공영의 증진, 통일의 촉진이 구현되도록 적극성을 갖고 제작에 임한다. 프로그램 제작시 여러 가치가 충돌할 경우 인간 존엄성 존중, 민족이익 수호, 민족화해 증진 등의 가치를 판단의 우선가치로 삼는다.', '평화통일 보도 준칙', '제작실천 2', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M3', '제작실천 3: 냉전시대 관행 탈피', '냉전시대에 형성된 내면적 자기검열, 습관화된 분단의식, 누적된 선입견과 편견으로부터 자유로운 상태에서 프로그램을 제작한다. 냉전의식을 바탕으로 만들어진 가요·가곡·드라마·영화 등의 방송을 피하며, 갈등을 조장하는 불필요한 화면을 사용하지 않는다.', '평화통일 보도 준칙', '제작실천 3', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M4', '제작실천 4: 상업·선정주의 경계', '상업주의와 선정주의를 경계하며, 안일하고 편의적인 제작태도를 극복하기 위해 끊임없이 노력한다. 현재의 모든 방송행위가 미래의 통일민족문화와 직결된다는 것을 염두에 두고 프로그램 제작에 임한다.', '평화통일 보도 준칙', '제작실천 4', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M5', '제작실천 5: 다원주의 가치반영', '사회적 가치나 의견 등의 메시지를 시청취자에게 전달할 때는 제작진이 단정적 결론을 내리기보다 시청취자가 듣고 보며 스스로 판단할 수 있도록 한다. 통일과 관련된 다양한 의견을 가능한 한 가감없이 프로그램에 반영하도록 노력한다.', '평화통일 보도 준칙', '제작실천 5', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M6', '제작실천 6: 보도활용 제작 신중', '국내외 매체의 조선민주주의인민공화국 관련 보도를 근거로 가십·꽁트 프로그램을 제작할 경우 보도의 정확성, 취재원의 신뢰도, 보도 이면에 게재되어 있을 수 있는 정치적 의도 등을 충분히 검증한 뒤 방송하며, 무분별하게 인용하여 민족화합을 저해할 수 있는 내용으로 프로그램화하지 않는다.', '평화통일 보도 준칙', '제작실천 6', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M7', '제작실천 7: 생활문화 적극 소개', '정치적 통합을 넘어서는 남북 주민간의 사회·문화적 통합이 진정한 최종적 통일임을 인식해 조선민주주의인민공화국 주민들의 생활과 문화를 프로그램 소재로 적극 채택한다.', '평화통일 보도 준칙', '제작실천 7', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M8', '제작실천 8: 능동적인 자료 접근', '조선민주주의인민공화국에 대한 프로그램 제작시 정보의 편중성·부족상황을 극복하기 위하여 제작진 스스로 노력한다. 1차자료를 적극 활용하고, 각 분야 연구자 등 폭넓은 인적자원 확보에 각자가 능동적으로 힘쓴다.', '평화통일 보도 준칙', '제작실천 8', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M9', '제작실천 9: 남북차이 이해 노력', '언어·문화·생활·관습·가치관 등에서의 남북의 차이를 인정하고 이를 객관적으로 인식하기 위해 노력하며, 가능한 한 이 차이들을 희화적 소재로 삼지 않도록 한다.', '평화통일 보도 준칙', '제작실천 9', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('PRG-M10', '제작실천 10: 남북 동질성의 부각', '남북의 차이점보다는 같은 점을, 과거보다는 미래를 부각시킴으로써 미래지향적·통일지향적 방향으로 프로그램 제작에 힘쓴다.', '평화통일 보도 준칙', '제작실천 10', 3, '도메인 특화 규범 (남북관계·통일 보도)', NULL, 'unification_reporting', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HSD-P', '혐오표현 반대 미디어 실천 선언 전문', '혐오표현은 우리나라를 비롯한 많은 나라에서 사회문제로 대두되고 있습니다. 우리 헌법은 누구든지 정치적·경제적·사회적·문화적 생활의 모든 영역에 있어서 차별을 받지 아니한다고 천명하고 있습니다. 미디어는 사회의 혐오표현을 막고, 시민의 인권의식을 높임으로써 건강한 사회를 만드는 데 앞장서야 할 책임이 있습니다. 우리 미디어 종사자들은 막중한 저널리즘의 책무와 윤리의식 아래 모든 혐오표현, 나아가 어떠한 증오와 폭력의 선동에도 반대한다는 명확한 원칙을 밝힙니다.', '혐오표현 반대 미디어 실천 선언', '전문', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', FALSE),
  ('HSD-1', '혐오표현 인식과 주의 깊은 전달', '우리는 평소 혐오표현의 개념과 맥락, 해악을 충분히 인식하고, 다양한 사회현상과 발언 등에 혐오표현이 있는지 주의 깊게 살펴보고 전달하겠습니다.', '혐오표현 반대 미디어 실천 선언', '선언 1', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HSD-2', '통치 수단으로 이용된 관념 비판', '우리는 가부장제, 레드콤플렉스, 지역주의와 같이 통치 수단으로 이용되어온 관념들을 당연한 ''사회윤리''로 포장하거나 ''미덕''으로 치부하지 않겠습니다.', '혐오표현 반대 미디어 실천 선언', '선언 2', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HSD-3', '사회적 소수자 배제 혐오표현 대응', '우리는 성소수자, 이주민, 난민, 북한이탈주민 등 사회적 소수자를 열등한 존재로 규정하고, 편견을 확산시키거나, 이들이 위험을 야기할 것이라는 공포를 부추겨 그들을 사회에서 배제하는 혐오표현에 적극 대응하겠습니다.', '혐오표현 반대 미디어 실천 선언', '선언 3', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HSD-4', '사회적 영향력자 혐오표현 비판', '우리는 주요 정치인, 고위 공무원, 종교 지도자 등 사회적 영향력이 큰 사람이 하는 혐오표현은 더욱 엄격하게 비판적으로 바라보겠습니다.', '혐오표현 반대 미디어 실천 선언', '선언 4', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HSD-5', '가짜뉴스·왜곡 정보 기반 혐오표현 팩트체크', '우리는 가짜뉴스나 왜곡된 정보에 기반한 혐오표현은 철저한 팩트체크를 통해 비판적으로 전달하겠습니다.', '혐오표현 반대 미디어 실천 선언', '선언 5', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
  ('HSD-6', '위기 상황에서의 혐오표현 경계', '우리는 경제적 불황, 범죄, 재난, 전염병 등이 발생했을 때 혐오표현이 많이 발생한다는 점을 이해하고, 인권의 측면에서 더욱 면밀히 살피고 전하겠습니다.', '혐오표현 반대 미디어 실천 선언', '선언 6', 4, '선언적 규범 (혐오표현 반대)', NULL, 'hate_speech', 'ko-KR', 1, TRUE, '2026-03-15', TRUE),
