INSERT INTO public.pattern_relations (source_pattern_id, target_pattern_id, relation_type, description, source, confidence, verified)
SELECT sp.id, tp.id, v.rel_type, v.desc_text, 'manual', 1.0, TRUE
FROM (VALUES
  ('1-1-1', '1-1-4', 'variant_of', '교차참조: 1-1-1 → 1-1-4'),
  ('1-1-5', '1-3-2', 'variant_of', '교차참조: 1-1-5 → 1-3-2'),
  ('1-4-1', '1-1-1', 'variant_of', '교차참조: 1-4-1 → 1-1-1'),
  ('1-4-1', '1-1-2', 'variant_of', '교차참조: 1-4-1 → 1-1-2'),
  ('1-4-1', '1-3-2', 'variant_of', '교차참조: 1-4-1 → 1-3-2'),
  ('1-4-2', '1-1-1', 'variant_of', '교차참조: 1-4-2 → 1-1-1'),
  ('1-4-2', '1-7-3', 'variant_of', '교차참조: 1-4-2 → 1-7-3'),
  ('1-4-2', '1-8-2', 'variant_of', '교차참조: 1-4-2 → 1-8-2'),
